func TestProofSpecProtoMarshal(t *testing.T) {
	t.Run("nil receiver returns nil", func(t *testing.T) {
		var nilSpec *ics23.ProofSpec
		uassert.Equal(t, 0, len(nilSpec.ProtoMarshal()))
	})

	t.Run("matches expected wire format for IavlSpec", func(t *testing.T) {
		bz := ics23.IavlSpec().ProtoMarshal()
		// Field 1 (LeafSpec, len=9):  0a 09 <leaf bytes>
		// Field 2 (InnerSpec, len=12):12 0c <inner bytes>
		// Fields 3,4,5: omitted (zero defaults)
		want := "0a090801180120012a0100" + "120c0a02000110211804200c3001"
		uassert.Equal(t, want, hex.EncodeToString(bz))
	})

	t.Run("optional fields are emitted when set", func(t *testing.T) {
		spec := &ics23.ProofSpec{
			MaxDepth:                   8,
			MinDepth:                   1,
			PrehashKeyBeforeComparison: true,
		}
		bz := spec.ProtoMarshal()
		// Field 3 (MaxDepth=8):                         18 08
		// Field 4 (MinDepth=1):                         20 01
		// Field 5 (PrehashKeyBeforeComparison=true):    28 01
		uassert.Equal(t, "180820012801", hex.EncodeToString(bz))
	})
}

func TestIsLeftNeighbor_NoPanicOnEdgeCases(cur realm, t *testing.T) {
	spec := ics23.IavlSpec().InnerSpec
	childSize := int(spec.ChildSize)

	validOp := func() *ics23.InnerOp {
		return &ics23.InnerOp{Prefix: []byte("aaaa"), Suffix: make([]byte, childSize)}
	}
	convergingOp := func() *ics23.InnerOp {
		return &ics23.InnerOp{Prefix: []byte("aaaa"), Suffix: make([]byte, childSize)}
	}
	malformedOp := func() *ics23.InnerOp {
		return &ics23.InnerOp{Prefix: make([]byte, 100), Suffix: nil}
	}

	cases := []struct {
		name      string
		left      []*ics23.InnerOp
		right     []*ics23.InnerOp
		expectErr bool
	}{
		{"empty left path", nil, []*ics23.InnerOp{validOp()}, false},
		{"empty right path", []*ics23.InnerOp{validOp()}, nil, false},
		{"common suffix exhausted", []*ics23.InnerOp{convergingOp()}, []*ics23.InnerOp{convergingOp()}, false},
		{"malformed left prefix", []*ics23.InnerOp{malformedOp()}, []*ics23.InnerOp{validOp()}, true},
		{"malformed right prefix", []*ics23.InnerOp{validOp()}, []*ics23.InnerOp{malformedOp()}, true},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			var (
				ok  bool
				err error
			)
			uassert.NotPanics(t, cur, func() {
				ok, err = ics23.IsLeftNeighbor(spec, tc.left, tc.right)
			})
			uassert.False(t, ok, "expected isNeighbor=false")
			if tc.expectErr {
				uassert.Error(t, err, "expected error for malformed input")
			} else {
				uassert.NoError(t, err)
			}
		})
	}
}

package ics23

import (
	"gno.land/p/aib/encoding/proto"
)

// GetSDKSpecs returns the proof specs of an SDK chain.
func GetSDKProofSpecs() []*ProofSpec {
	return []*ProofSpec{IavlSpec(), TendermintSpec()}
}

// IavlSpec constrains the format from proofs-iavl (iavl merkle proofs)
func IavlSpec() *ProofSpec {
	return &ProofSpec{
		LeafSpec: &LeafOp{
			Prefix:       []byte{0},
			PrehashKey:   HashOp_NO_HASH,
			Hash:         HashOp_SHA256,
			PrehashValue: HashOp_SHA256,
			Length:       LengthOp_VAR_PROTO,
		},
		InnerSpec: &InnerSpec{
			ChildOrder:      []int32{0, 1},
			MinPrefixLength: 4,
			MaxPrefixLength: 12,
			ChildSize:       33, // (with length byte)
			EmptyChild:      nil,
			Hash:            HashOp_SHA256,
		},
	}
}

// TendermintSpec constrains the format from proofs-tendermint (crypto/merkle SimpleProof)
func TendermintSpec() *ProofSpec {
	return &ProofSpec{
		LeafSpec: &LeafOp{
			Prefix:       []byte{0},
			PrehashKey:   HashOp_NO_HASH,
			Hash:         HashOp_SHA256,
			PrehashValue: HashOp_SHA256,
			Length:       LengthOp_VAR_PROTO,
		},
		InnerSpec: &InnerSpec{
			ChildOrder:      []int32{0, 1},
			MinPrefixLength: 1,
			MaxPrefixLength: 1,
			ChildSize:       32, // (no length byte)
			Hash:            HashOp_SHA256,
		},
	}
}

// ProofSpec defines what the expected parameters are for a given proof type.
// This can be stored in the client and used to validate any incoming proofs.
//
// verify(ProofSpec, Proof) -> Proof | Error
//
// As demonstrated in tests, if we don't fix the algorithm used to calculate the
// LeafHash for a given tree, there are many possible key-value pairs that can
// generate a given hash (by interpretting the preimage differently).
// We need this for proper security, requires client knows a priori what
// tree format server uses. But not in code, rather a configuration object.
type ProofSpec struct {
	// any field in the ExistenceProof must be the same as in this spec.
	// except Prefix, which is just the first bytes of prefix (spec can be longer)
	LeafSpec  *LeafOp
	InnerSpec *InnerSpec
	// max_depth (if > 0) is the maximum number of InnerOps allowed (mainly for fixed-depth tries)
	// the max_depth is interpreted as 128 if set to 0
	MaxDepth int32
	// min_depth (if > 0) is the minimum number of InnerOps allowed (mainly for fixed-depth tries)
	MinDepth int32
	// prehash_key_before_comparison is a flag that indicates whether to use the
	// prehash_key specified by LeafOp to compare lexical ordering of keys for
	// non-existence proofs.
	PrehashKeyBeforeComparison bool
}

// InnerSpec contains all store-specific structure info to determine if two proofs from a
// given store are neighbors.
//
// This enables:
//
// isLeftMost(spec: InnerSpec, op: InnerOp)
// isRightMost(spec: InnerSpec, op: InnerOp)
// isLeftNeighbor(spec: InnerSpec, left: InnerOp, right: InnerOp)
type InnerSpec struct {
	// Child order is the ordering of the children node, must count from 0
	// iavl tree is [0, 1] (left then right)
	// merk is [0, 2, 1] (left, right, here)
	ChildOrder      []int32
	ChildSize       int32
	MinPrefixLength int32
	MaxPrefixLength int32
	// empty child is the prehash image that is used when one child is nil (eg. 20 bytes of 0)
	EmptyChild []byte
	// hash is the algorithm that must be used for each InnerOp
	Hash HashOp
}

// ProtoMarshal returns the proto3 wire encoding of the ProofSpec, matching
// the format produced by gogoproto in cosmos/ics23. A nil receiver is encoded
// as an empty byte slice (proto3 unset message).
func (p *ProofSpec) ProtoMarshal() []byte {
	if p == nil {
		return nil
	}
	var bz []byte
	bz = proto.AppendLengthDelimited(bz, 1, p.LeafSpec.ProtoMarshal())
	bz = proto.AppendLengthDelimited(bz, 2, p.InnerSpec.ProtoMarshal())
	bz = proto.AppendVarint(bz, 3, uint64(int64(p.MaxDepth)))
	bz = proto.AppendVarint(bz, 4, uint64(int64(p.MinDepth)))
	if p.PrehashKeyBeforeComparison {
		bz = proto.AppendVarint(bz, 5, 1)
	}
	return bz
}

// ProtoMarshal returns the proto3 wire encoding of the LeafOp.
func (p *LeafOp) ProtoMarshal() []byte {
	if p == nil {
		return nil
	}
	var bz []byte
	bz = proto.AppendVarint(bz, 1, uint64(int64(p.Hash)))
	bz = proto.AppendVarint(bz, 2, uint64(int64(p.PrehashKey)))
	bz = proto.AppendVarint(bz, 3, uint64(int64(p.PrehashValue)))
	bz = proto.AppendVarint(bz, 4, uint64(int64(p.Length)))
	bz = proto.AppendLengthDelimited(bz, 5, p.Prefix)
	return bz
}

// ProtoMarshal returns the proto3 wire encoding of the InnerSpec. ChildOrder
// is encoded as a packed repeated int32 field per proto3 default.
func (p *InnerSpec) ProtoMarshal() []byte {
	if p == nil {
		return nil
	}
	var bz []byte
	bz = proto.AppendPackedVarintInt32(bz, 1, p.ChildOrder)
	bz = proto.AppendVarint(bz, 2, uint64(int64(p.ChildSize)))
	bz = proto.AppendVarint(bz, 3, uint64(int64(p.MinPrefixLength)))
	bz = proto.AppendVarint(bz, 4, uint64(int64(p.MaxPrefixLength)))
	bz = proto.AppendLengthDelimited(bz, 5, p.EmptyChild)
	bz = proto.AppendVarint(bz, 6, uint64(int64(p.Hash)))
	return bz
}

package testing

import (
	"encoding/hex"

	"gno.land/p/aib/ics23"
)

func NewExistenceProof(spec *ics23.ProofSpec, key []byte, value, leaf string, paths [][]string) *ics23.ExistenceProof {
	ep := &ics23.ExistenceProof{
		Key:   key,
		Value: hexDec(value),
		Leaf: &ics23.LeafOp{
			Hash:         spec.LeafSpec.Hash,
			PrehashKey:   spec.LeafSpec.PrehashKey,
			PrehashValue: spec.LeafSpec.PrehashValue,
			Length:       spec.LeafSpec.Length,
			Prefix:       hexDec(leaf),
		},
	}
	for i, _ := range paths {
		ep.Path = append(ep.Path, &ics23.InnerOp{
			Hash:   spec.InnerSpec.Hash,
			Prefix: hexDec(paths[i][0]),
			Suffix: hexDec(paths[i][1]),
		})
	}
	return ep
}

func hexDec(s string) []byte {
	b, err := hex.DecodeString(s)
	if err != nil {
		panic(err)
	}
	return b
}

package types

import (
	"math"
	"regexp"
	"strconv"
	"strings"

	"gno.land/p/aib/ibc/host"
	"gno.land/p/nt/ufmt/v0"
)

// ValidateClientType validates the client type. It cannot be blank or empty.
// It must be a valid client identifier when used with '0' or the maximum
// uint64 as the sequence.
func ValidateClientType(clientType string) error {
	if strings.TrimSpace(clientType) == "" {
		return ufmt.Errorf("client type cannot be blank")
	}

	smallestPossibleClientID := FormatClientIdentifier(clientType, 0)
	largestPossibleClientID := FormatClientIdentifier(clientType, uint64(math.MaxUint64))

	// IsValidClientID will check client type format and if the sequence is a uint64
	if !IsValidClientID(smallestPossibleClientID) {
		return ufmt.Errorf("not a valid clientID: %s", smallestPossibleClientID)
	}

	if err := host.ClientIdentifierValidator(smallestPossibleClientID); err != nil {
		return err
	}
	if err := host.ClientIdentifierValidator(largestPossibleClientID); err != nil {
		return err
	}

	return nil
}

// FormatClientIdentifier returns the client identifier with the sequence appended.
// This is an SDK specific format not enforced by IBC protocol.
func FormatClientIdentifier(clientType string, sequence uint64) string {
	return ufmt.Sprintf("%s-%d", clientType, sequence)
}

// IsClientIDFormat checks if a clientID is in the format required on the SDK
// for parsing client identifiers. The client identifier must be in the form:
// `{client-type}-{N}` which per the specification only permits ASCII for the
// {client-type} segment and 1 to 20 digits for the {N} segment.
// `([\w-]+\w)?` allows for a letter or hyphen, with the {client-type} starting
// with a letter and ending with a letter, i.e.
// `letter+(letter|hyphen+letter)?`.
var IsClientIDFormat = regexp.MustCompile(`^\w+([\w-]+\w)?-[0-9]{1,20}$`).MatchString

// IsValidClientID checks if the clientID is valid and can be parsed into the client
// identifier format.
func IsValidClientID(clientID string) bool {
	_, _, err := ParseClientIdentifier(clientID)
	return err == nil
}

// ParseClientIdentifier parses the client type and sequence from the client identifier.
func ParseClientIdentifier(clientID string) (string, uint64, error) {
	if !IsClientIDFormat(clientID) {
		return "", 0, ufmt.Errorf("invalid client identifier %s is not in format: `{client-type}-{N}`", clientID)
	}

	splitStr := strings.Split(clientID, "-")
	lastIndex := len(splitStr) - 1

	clientType := strings.Join(splitStr[:lastIndex], "-")
	if strings.TrimSpace(clientType) == "" {
		return "", 0, ufmt.Errorf("client identifier must be in format: `{client-type}-{N}` and client type cannot be blank")
	}

	sequence, err := strconv.ParseUint(splitStr[lastIndex], 10, 64)
	if err != nil {
		return "", 0, ufmt.Errorf("failed to parse client identifier sequence")
	}

	return clientType, sequence, nil
}

