package types

import (
	"chain/runtime"
	"encoding/binary"
	"regexp"
	"strconv"
	"strings"

	"gno.land/p/aib/encoding/proto"
	"gno.land/p/nt/ufmt/v0"
)

// Height is a monotonically increasing data type
// that can be compared against another Height for the purposes of updating and
// freezing clients
//
// Normally the RevisionHeight is incremented at each height while keeping
// RevisionNumber the same. However some consensus algorithms may choose to
// reset the height in certain conditions e.g. hard forks, state-machine
// breaking changes In these cases, the RevisionNumber is incremented so that
// height continues to be monitonically increasing even as the RevisionHeight
// gets reset
//
// Please note that json tags for generated Go code are overridden to explicitly exclude the omitempty jsontag.
// This enforces the Go json marshaller to always emit zero values for both revision_number and revision_height.
type Height struct {
	// the revision that the client is currently on
	RevisionNumber uint64
	// the height within the given revision
	RevisionHeight uint64
}

func NewHeight(revision, height uint64) Height {
	return Height{
		RevisionNumber: revision,
		RevisionHeight: height,
	}
}

// ParseHeight is a utility function that takes a string representation of the
// height and returns a Height struct.
func ParseHeight(heightStr string) (Height, error) {
	splitStr := strings.Split(heightStr, "/")
	if len(splitStr) != 2 {
		return Height{}, ufmt.Errorf("expected height string format: {revision}/{height}. Got: %s", heightStr)
	}
	revisionNumber, err := strconv.ParseUint(splitStr[0], 10, 64)
	if err != nil {
		return Height{}, ufmt.Errorf("invalid revision number. parse err: %s", err)
	}
	revisionHeight, err := strconv.ParseUint(splitStr[1], 10, 64)
	if err != nil {
		return Height{}, ufmt.Errorf("invalid revision height. parse err: %s", err)
	}
	return NewHeight(revisionNumber, revisionHeight), nil
}

func ZeroHeight() Height { return Height{} }

func (h Height) String() string {
	return ufmt.Sprintf("%d/%d", h.RevisionNumber, h.RevisionHeight)
}

// StringNatSort returns a natural sortable representation of height that can
// be used for store keys.
func (h Height) StringNatSort() string {
	bz := make([]byte, 16)
	binary.BigEndian.PutUint64(bz, h.RevisionNumber)
	binary.BigEndian.PutUint64(bz[8:], h.RevisionHeight)
	return string(bz)
}

// ParseHeightNatSort is a utility function that takes a string nat sorted
// representation of the height (see StringBatSort) and returns a Height
// struct.
func ParseHeightNatSort(heightNatSort string) (h Height) {
	bz := []byte(heightNatSort)
	h.RevisionNumber = binary.BigEndian.Uint64(bz)
	h.RevisionHeight = binary.BigEndian.Uint64(bz[8:])
	return
}

// GTE Helper comparison function returns true if h >= other
func (h Height) GTE(other Height) bool {
	cmp := h.Compare(other)
	return cmp >= 0
}

// GT Helper comparison function returns true if h > other
func (h Height) GT(other Height) bool {
	return h.Compare(other) == 1
}

// LTE Helper comparison function returns true if h <= other
func (h Height) LTE(other Height) bool {
	cmp := h.Compare(other)
	return cmp <= 0
}

// LT Helper comparison function returns true if h < other
func (h Height) LT(other Height) bool {
	return h.Compare(other) == -1
}

// EQ Helper comparison function returns true if h == other
func (h Height) EQ(other Height) bool {
	return h.Compare(other) == 0
}

// IsZero returns true if height revision and revision-height are both 0
func (h Height) IsZero() bool {
	return h.RevisionNumber == 0 && h.RevisionHeight == 0
}

// Compare implements a method to compare two heights. When comparing two heights a, b
// we can call a.Compare(b) which will return
// -1 if a < b
// 0  if a = b
// 1  if a > b
//
// It first compares based on revision numbers, whichever has the higher revision number is the higher height
// If revision number is the same, then the revision height is compared
func (h Height) Compare(height Height) int64 {
	if h.RevisionNumber < height.RevisionNumber {
		return -1
	}
	if h.RevisionNumber > height.RevisionNumber {
		return 1
	}
	if h.RevisionHeight < height.RevisionHeight {
		return -1
	}
	if h.RevisionHeight > height.RevisionHeight {
		return 1
	}
	return 0
}

// GetSelfHeight is a utility function that returns self height given context.
// Revision number is retrieved from runtime.ChainID()
func GetSelfHeight() Height {
	revision := ParseChainID(runtime.ChainID())
	return NewHeight(revision, uint64(runtime.ChainHeight()))
}

// IsRevisionFormat checks if a chainID is in the format required for parsing
// revisions
// The chainID must be in the form: `{chainID}-{revision}`.
// 24-host may enforce stricter checks on chainID
var IsRevisionFormat = regexp.MustCompile(`^.*[^\n-]-{1}[1-9][0-9]*$`).MatchString

// ParseChainID is a utility function that returns a revision number from the
// given ChainID.
// ParseChainID attempts to parse a chain id in the format:
// `{chainID}-{revision}` and return the revisionnumber as a uint64.
// If the chainID is not in the expected format, a default revision value of 0
// is returned.
func ParseChainID(chainID string) uint64 {
	if !IsRevisionFormat(chainID) {
		// chainID is not in revision format, return 0 as default
		return 0
	}
	splitStr := strings.Split(chainID, "-")
	revision, err := strconv.ParseUint(splitStr[len(splitStr)-1], 10, 64)
	// sanity check: error should always be nil since regex only allows numbers in last element
	if err != nil {
		panic(ufmt.Errorf("regex allowed non-number value as last split element for chainID: %s", chainID))
	}
	return revision
}

// SetRevisionNumber takes a chainID in valid revision format and swaps the
// revision number in the chainID with the given revision number.
func SetRevisionNumber(chainID string, revision uint64) (string, error) {
	if !IsRevisionFormat(chainID) {
		return "", ufmt.Errorf("chainID is not in revision format: %s", chainID)
	}

	splitStr := strings.Split(chainID, "-")
	// swap out revision number with given revision
	splitStr[len(splitStr)-1] = strconv.FormatUint(revision, 10)
	return strings.Join(splitStr, "-"), nil
}

func (h Height) ProtoMarshal() (bz []byte) {
	bz = proto.AppendVarint(bz, 1, h.RevisionNumber)
	bz = proto.AppendVarint(bz, 2, h.RevisionHeight)
	return
}

package types

import "strings"

// MerklePath is the path used to verify commitment proofs, which can be an
// arbitrary structured object (defined by a commitment type).
// ICS-23 verification supports membership proofs for nested merkle trees.
// The ICS-24 standard provable keys MUST be stored in the lowest level tree
// with an optional prefix.
// The IC24 provable tree may then be stored in a higher level tree(s) that
// hash up to the root hash stored in the consensus state of the client.
// Each element of the path represents the key of a merkle tree from the root
// to the leaf.
// The elements of the path before the final element must be the path to the
// tree that contains the ICS24 provable store. Thus, it should remain constant
// for all ICS24 proofs.
// The final element of the path is the key of the leaf in the ICS24 provable
// store, thus IBC core will append the ICS24 path to the final element of the
// MerklePath stored in the counterparty to create the full path to the leaf
// for proof verification.
//
// Examples:
// Cosmos SDK:
// The Cosmos SDK commits to a multi-tree where each store is an IAVL tree and
// all store hashes are hashed in a simple merkle tree to get the final root
// hash. Thus, the MerklePath in the counterparty MerklePrefix has the
// following structure: ["ibc", ""]
// The core IBC handler will append the ICS24 path to the final element of the
// MerklePath like so: ["ibc", "{packetCommitmentPath}"] which will then be
// used for final verification.
type MerklePath struct {
	KeyPath [][]byte
}

func (mp MerklePath) String() string {
	var strs []string
	for _, p := range mp.KeyPath {
		strs = append(strs, string(p))
	}
	return "[" + strings.Join(strs, ", ") + "]"
}

// BuildMerklePath takes the merkle path prefix and an ICS24 path and builds a
// new path by appending the ICS24 path to the last element of the merkle path
// prefix.
func BuildMerklePath(prefix [][]byte, path []byte) MerklePath {
	prefixLength := len(prefix)
	if prefixLength == 0 {
		panic("cannot build merkle path with empty prefix")
	}

	// copy prefix to avoid modifying the original slice
	fullPath := make([][]byte, len(prefix))
	for i, p := range prefix {
		fullPath[i] = make([]byte, len(p))
		copy(fullPath[i], p)
	}
	// append path to last element
	fullPath[prefixLength-1] = append(fullPath[prefixLength-1], path...)
	return MerklePath{KeyPath: fullPath}
}

package types

import (
	"crypto/sha256"
	"encoding/base64"
	"errors"

	"gno.land/p/aib/ibc/host"
	"gno.land/p/aib/ics23"
	"gno.land/p/nt/ufmt/v0"
	"gno.land/p/onbloc/json"
)

// MsgSendPacket sends an outgoing IBC packet.
type MsgSendPacket struct {
	SourceClient string
	// TimeoutTimestamp holds the seconds after which the packet times out.
	TimeoutTimestamp uint64
	Payloads         []Payload
}

// NewMsgSendPacket creates a new MsgSendPacket instance.
func NewMsgSendPacket(sourceClient string, timeoutTimestamp uint64, payloads ...Payload) *MsgSendPacket {
	return &MsgSendPacket{
		SourceClient:     sourceClient,
		TimeoutTimestamp: timeoutTimestamp,
		Payloads:         payloads,
	}
}

// ValidateBasic performs basic checks on a MsgSendPacket.
func (msg *MsgSendPacket) ValidateBasic() error {
	if err := host.ClientIdentifierValidator(msg.SourceClient); err != nil {
		return err
	}

	if msg.TimeoutTimestamp == 0 {
		return ufmt.Errorf("timeout must not be 0")
	}

	if len(msg.Payloads) == 0 {
		return ufmt.Errorf("payload length must be greater than 0")
	}

	for i, pd := range msg.Payloads {
		if err := pd.ValidateBasic(); err != nil {
			return ufmt.Errorf("invalid payload #%d: %v", i, err)
		}
	}
	return nil
}

// MsgRecvPacket receives an incoming IBC packet.
type MsgRecvPacket struct {
	Packet          Packet
	ProofCommitment []ics23.CommitmentProof
	ProofHeight     Height
}

// ValidateBasic performs basic checks on a MsgRecvPacket.
func (msg *MsgRecvPacket) ValidateBasic() error {
	if len(msg.ProofCommitment) == 0 {
		return ufmt.Errorf("proof commitment can not be empty")
	}
	return msg.Packet.ValidateBasic()
}

// MsgAcknowledgement receives incoming IBC acknowledgement.
type MsgAcknowledgement struct {
	Packet          Packet
	Acknowledgement Acknowledgement
	ProofAcked      []ics23.CommitmentProof
	ProofHeight     Height
}

// ValidateBasic performs basic checks on a MsgAcknowledgement.
func (msg *MsgAcknowledgement) ValidateBasic() error {
	if len(msg.ProofAcked) == 0 {
		return errors.New("cannot submit an empty acknowledgement proof")
	}
	for i, proof := range msg.ProofAcked {
		if proof.GetExist() == nil {
			return ufmt.Errorf("invalid commitment proof #%d: proof.GetExists() is nil", i)
		}
	}

	if err := msg.Acknowledgement.Validate(); err != nil {
		return err
	}

	return msg.Packet.ValidateBasic()
}

func UniversalErrorAcknowledgement() []byte {
	bz := sha256.Sum256([]byte("UNIVERSAL_ERROR_ACKNOWLEDGEMENT"))
	return bz[:]
}

// AppAcknowledgement is the recommended acknowledgement format to be used by
// app-specific protocols.
type AppAcknowledgement struct {
	Response AppAcknowledgementResponse
}

type AppAcknowledgementResponse struct {
	Result []byte
	Error  string
}

func NewErrorAppAcknowledgement(err error) AppAcknowledgement {
	return AppAcknowledgement{Response: AppAcknowledgementResponse{Error: err.Error()}}
}

func NewResultAppAcknowledgement(result []byte) AppAcknowledgement {
	return AppAcknowledgement{
		Response: AppAcknowledgementResponse{
			Result: result,
		},
	}
}

func (a AppAcknowledgement) Success() bool {
	return a.Response.Error == ""
}

func (a *AppAcknowledgement) MarshalJSON() []byte {
	var node *json.Node
	if a.Response.Error != "" {
		node = json.ObjectNode("", map[string]*json.Node{
			"error": json.StringNode("", a.Response.Error),
		})
	} else {
		node = json.ObjectNode("", map[string]*json.Node{
			"result": json.StringNode("", base64.StdEncoding.EncodeToString(a.Response.Result)),
		})
	}
	bz, _ := json.Marshal(node)
	return bz
}

func (a *AppAcknowledgement) UnmarshalJSON(bz []byte) error {
	root, err := json.Unmarshal(bz)
	if err != nil {
		return err
	}
	result, err := root.GetKey("result")
	if err != nil {
		rerror, err := root.GetKey("error")
		if err != nil {
			return err
		}
		a.Response = AppAcknowledgementResponse{Error: rerror.MustString()}
		return nil
	}
	resBz, err := base64.StdEncoding.DecodeString(result.MustString())
	if err != nil {
		return err
	}
	a.Response = AppAcknowledgementResponse{Result: resBz}
	return nil
}

// MsgTimeout receives timed-out packet
type MsgTimeout struct {
	Packet          Packet
	ProofUnreceived []ics23.CommitmentProof
	ProofHeight     Height
}

func (msg *MsgTimeout) ValidateBasic() error {
	if len(msg.ProofUnreceived) == 0 {
		return errors.New("cannot submit an empty timeout proof")
	}
	return msg.Packet.ValidateBasic()
}

package types

import (
	"bytes"
	"errors"
	"strings"

	"gno.land/p/aib/encoding/proto"
	"gno.land/p/aib/ibc/host"
	"gno.land/p/nt/ufmt/v0"
)

// PacketStatus specifies the status of a RecvPacketResult.
type PacketStatus int32

const (
	// PACKET_STATUS_UNSPECIFIED indicates an unknown packet status.
	PacketStatus_NONE PacketStatus = 0
	// PACKET_STATUS_SUCCESS indicates a successful packet receipt.
	PacketStatus_Success PacketStatus = 1
	// PACKET_STATUS_FAILURE indicates a failed packet receipt.
	PacketStatus_Failure PacketStatus = 2
	// PACKET_STATUS_ASYNC indicates that the packet was received and its
	// acknowledgement will be written later by the application.
	PacketStatus_Async PacketStatus = 3
)

// Packet defines a type that carries data across different chains through IBC
type Packet struct {
	// number corresponds to the order of sends and receives, where a Packet
	// with an earlier sequence number must be sent and received before a Packet
	// with a later sequence number.
	Sequence uint64
	// identifies the sending client on the sending chain.
	SourceClient string
	// identifies the receiving client on the receiving chain.
	DestinationClient string
	// timeout timestamp in seconds after which the packet times out.
	TimeoutTimestamp uint64
	// a list of payloads, each one for a specific application.
	Payloads []Payload
}

// NewPacket constructs a new packet.
func NewPacket(sequence uint64, sourceClient, destinationClient string, timeoutTimestamp uint64, payloads ...Payload) Packet {
	return Packet{
		Sequence:          sequence,
		SourceClient:      sourceClient,
		DestinationClient: destinationClient,
		TimeoutTimestamp:  timeoutTimestamp,
		Payloads:          payloads,
	}
}

const MaximumPayloadsSize = 262144 // 256 KiB. This is the maximum size of all payloads combined

// ValidateBasic validates that a Packet satisfies the basic requirements.
func (p Packet) ValidateBasic() error {
	if len(p.Payloads) == 0 {
		return ufmt.Errorf("payload length must be greater than 0")
	}

	totalPayloadsSize := 0
	for i, pd := range p.Payloads {
		if err := pd.ValidateBasic(); err != nil {
			return ufmt.Errorf("invalid Payload #%d: %v", i, err)
		}
		totalPayloadsSize += len(pd.Value)
	}

	if totalPayloadsSize > MaximumPayloadsSize {
		return ufmt.Errorf("packet data bytes cannot exceed %d bytes", MaximumPayloadsSize)
	}

	if err := host.ClientIdentifierValidator(p.SourceClient); err != nil {
		return ufmt.Errorf("invalid source ID: %v", err)
	}
	if err := host.ClientIdentifierValidator(p.DestinationClient); err != nil {
		return ufmt.Errorf("invalid destination ID: %v", err)
	}

	if p.Sequence == 0 {
		return ufmt.Errorf("packet sequence cannot be 0")
	}
	if p.TimeoutTimestamp == 0 {
		return ufmt.Errorf("packet timeout timestamp cannot be 0")
	}

	return nil
}

// ProtoMarshal returns the protobuf encoding of a Packet.
//
//	message Packet {
//	  uint64 sequence = 1;
//	  string source_client = 2;
//	  string destination_client = 3;
//	  uint64 timeout_timestamp = 4;
//	  repeated Payload payloads = 5 [(gogoproto.nullable) = false];
//	}
func (p Packet) ProtoMarshal() (buf []byte) {
	// Field 1: sequence (varint)
	buf = proto.AppendVarint(buf, 1, uint64(p.Sequence))

	// Field 2: source_client (length-delimited)
	buf = proto.AppendLengthDelimited(buf, 2, []byte(p.SourceClient))

	// Field 3: destination_client (length-delimited)
	buf = proto.AppendLengthDelimited(buf, 3, []byte(p.DestinationClient))

	// Field 4: timeout_timestamp (varint)
	buf = proto.AppendVarint(buf, 4, p.TimeoutTimestamp)

	// Field 5: payloads
	for _, payload := range p.Payloads {
		bz := payload.ProtoMarshal()
		buf = proto.AppendLengthDelimited(buf, 5, bz)
	}
	return
}

type Payload struct {
	// specifies the source port of the packet.
	SourcePort string
	// specifies the destination port of the packet.
	DestinationPort string
	// version of the specified application.
	Version string
	// the encoding used for the provided value.
	Encoding string
	// the raw bytes for the payload.
	Value []byte
}

// NewPayload constructs a new Payload
func NewPayload(sourcePort, destPort, version, encoding string, value []byte) Payload {
	return Payload{
		SourcePort:      sourcePort,
		DestinationPort: destPort,
		Version:         version,
		Encoding:        encoding,
		Value:           value,
	}
}

// ValidateBasic validates a Payload.
func (p Payload) ValidateBasic() error {
	if err := host.PortIdentifierValidator(p.SourcePort); err != nil {
		return ufmt.Errorf("invalid source port: %v", err)
	}
	if err := host.PortIdentifierValidator(p.DestinationPort); err != nil {
		return ufmt.Errorf("invalid destination port: %v", err)
	}
	if strings.TrimSpace(p.Version) == "" {
		return ufmt.Errorf("payload version cannot be empty")
	}
	if strings.TrimSpace(p.Encoding) == "" {
		return ufmt.Errorf("payload encoding cannot be empty")
	}
	if len(p.Value) == 0 {
		return ufmt.Errorf("payload value cannot be empty")
	}
	return nil
}

// ProtoMarshal returns the protobuf encoding of a Payload.
//
//	message Payload {
//	  string source_port = 1;
//	  string destination_port = 2;
//	  string version = 3;
//	  string encoding = 4;
//	  bytes value = 5;
//	}
func (p Payload) ProtoMarshal() []byte {
	var buf []byte

	// Field 1: source_port (length-delimited)
	buf = proto.AppendLengthDelimited(buf, 1, []byte(p.SourcePort))

	// Field 2: destination_port (length-delimited)
	buf = proto.AppendLengthDelimited(buf, 2, []byte(p.DestinationPort))

	// Field 3: version (length-delimited)
	buf = proto.AppendLengthDelimited(buf, 3, []byte(p.Version))

	// Field 4: encoding (length-delimited)
	buf = proto.AppendLengthDelimited(buf, 4, []byte(p.Encoding))

	// Field 5: value (length-delimited)
	buf = proto.AppendLengthDelimited(buf, 5, p.Value)

	return buf
}

// RecvPacketResult speecifies the status of a packet as well as the acknowledgement bytes.
type RecvPacketResult struct {
	// status of the packet
	Status PacketStatus
	// acknowledgement of the packet
	Acknowledgement []byte
}

// Acknowledgement contains a list of all ack results associated with a single packet.
// In the case of a successful receive, the acknowledgement will contain an app acknowledgement
// for each application that received a payload in the same order that the payloads were sent
// in the packet.
// If the receive is not successful, the acknowledgement will contain a single app acknowledgment
// which will be a constant error acknowledgment as defined by the IBC v2 protocol.
type Acknowledgement struct {
	AppAcknowledgements [][]byte
}

// Validate performs a basic validation of the acknowledgement
func (ack Acknowledgement) Validate() error {
	// acknowledgement list should be non-empty
	if len(ack.AppAcknowledgements) == 0 {
		return errors.New("app acknowledgements must be non-empty")
	}

	for _, a := range ack.AppAcknowledgements {
		// Each app acknowledgement should be non-empty
		if len(a) == 0 {
			return errors.New("app acknowledgement cannot be empty")
		}

		// Ensure that the app acknowledgement contains ErrorAcknowledgement
		// **if and only if** the app acknowledgement list has a single element
		if len(ack.AppAcknowledgements) > 1 {
			if bytes.Equal(a, UniversalErrorAcknowledgement()) {
				return errors.New("cannot have the error acknowledgement in multi acknowledgement list")
			}
		}
	}

	return nil
}

// Success returns true if the acknowledgement is successful
// it implements the exported.Acknowledgement interface
func (ack Acknowledgement) Success() bool {
	return !bytes.Equal(ack.AppAcknowledgements[0], UniversalErrorAcknowledgement())
}

// ProtoMarshal returns the protobuf encoding of a Acknowledgement.
//
//	message Acknowledgement {
//	  repeated bytes app_acknowledgements = 1;
//	}
func (ack Acknowledgement) ProtoMarshal() (buf []byte) {
	for _, appAck := range ack.AppAcknowledgements {
		buf = append(buf, proto.AppendLengthDelimited(nil, 1, appAck)...)
	}
	return
}

package types_test

import (
	"encoding/hex"
	"strings"
	"testing"
	"time"

	"gno.land/p/aib/ibc/types"
