			packet = types.NewPacket(1, "channel-1", "channel-2", uint64(time.Now().Unix()), payload)
			tc.malleate()

			err := packet.ValidateBasic()

			if tc.expErr == "" {
				urequire.NoError(t, err)
				return
			}
			urequire.ErrorContains(t, err, tc.expErr)
		})
	}
}

func TestPacketProtoMarshal(t *testing.T) {
