func testVotesBytesToSign(t *testing.T, msg *tendermint.MsgHeader, expectedBytesToSign []string) {
	for idx, val := range msg.ValidatorSet.Validators {
		bz := msg.Commit.BytesToSign(msg.Header.ChainID, idx)
		if h := hex.EncodeToString(bz); h != expectedBytesToSign[idx] {
			t.Errorf("wrong bytes-to-sign, got %s, want %s", h, expectedBytesToSign[idx])
			continue
		}
		if msg.Commit.Signatures[idx].BlockIDFlag != tendermint.BlockIDFlagCommit {
			// skip non signed block
			continue
		}

		v := ed25519.Verify(val.PubKey, bz, msg.Commit.Signatures[idx].Signature)

		if !v {
			t.Errorf("failed to verify signature for validator index %d", idx)
		}
	}
}

func b64Dec(s string) []byte {
	bz, err := base64.StdEncoding.DecodeString(s)
	if err != nil {
		panic(err)
	}
	return bz
}

func toTime(s string) time.Time {
	t, err := time.Parse(time.RFC3339Nano, s)
	if err != nil {
		panic(err)
	}
	return t
}

func genAddr(seed string) []byte {
	return hash(seed)[:tendermint.AddressSize]
}

func genSignature(seed string) []byte {
	return hash(seed)[:tendermint.MaxSignatureSize]
}

func genPubkey(seed string) []byte {
	return hash(seed)[:32]
}

func hash(s string) []byte {
	h := sha256.Sum256([]byte(s))
	return h[:]
}

func newMsgHeader(chainID string, timestamp time.Time,
	apphash []byte, height uint64, trustedHeight types.Height,
	valset, nextValset, trustedValset *tendermint.ValidatorSet,
	signatures []tendermint.CommitSig) *tendermint.MsgHeader {
	header := &tendermint.Header{
		Version: tendermint.Consensus{
			Block: tendermint.BlockProtocol,
			App:   0,
		},
		ChainID: chainID,
		Height:  height,
		Time:    timestamp,
		LastBlockID: tendermint.BlockID{
			Hash: hash("last_block_hash"),
			PartSetHeader: tendermint.PartSetHeader{
				Total: 1,
				Hash:  hash("last_block_partset_hash"),
			},
		},
		LastCommitHash:     hash("last_commit_hash"),
		DataHash:           hash("data_hash"),
		ValidatorsHash:     valset.Hash(),
		NextValidatorsHash: nextValset.Hash(),
		ConsensusHash:      hash("consensus_hash"),
		AppHash:            apphash,
		LastResultsHash:    hash("last_results_hash"),
		EvidenceHash:       hash("evidence_hash"),
		ProposerAddress:    valset.Validators[0].Address,
	}

	return &tendermint.MsgHeader{
		Header: header,
		Commit: &tendermint.Commit{
			Height: height,
			Round:  0,
			BlockID: tendermint.BlockID{
				Hash: header.Hash(), // compute expected block hash
				PartSetHeader: tendermint.PartSetHeader{
					Total: 1,
					Hash:  hash("block_partset_hash"),
				},
			},
			Signatures: signatures,
		},
		ValidatorSet:      valset,
		TrustedHeight:     trustedHeight,
		TrustedValidators: trustedValset,
	}
}

package tendermint

import (
	"gno.land/p/aib/ibc/lightclient"
	"gno.land/p/nt/ufmt/v0"
)

// Misbehaviour is a wrapper over two conflicting Headers
// that implements Misbehaviour interface expected by ICS-02
type Misbehaviour struct {
	Header1 *MsgHeader
	Header2 *MsgHeader
}

// Implements lightclient.ClientMessage
func (Misbehaviour) ClientType() string {
	return lightclient.Tendermint
}

// Implements lightclient.ClientMessage
func (m Misbehaviour) ValidateBasic() error {
	if m.Header1 == nil {
		return ufmt.Errorf("misbehaviour Header1 cannot be nil")
	}
	if m.Header2 == nil {
		return ufmt.Errorf("misbehaviour Header2 cannot be nil")
	}
	if m.Header1.TrustedHeight.RevisionHeight == 0 {
		return ufmt.Errorf("misbehaviour Header1 cannot have zero revision height")
	}
	if m.Header2.TrustedHeight.RevisionHeight == 0 {
		return ufmt.Errorf("misbehaviour Header2 cannot have zero revision height")
	}
	if m.Header1.TrustedValidators == nil {
		return ufmt.Errorf("trusted validator set in Header1 cannot be empty")
	}
	if m.Header2.TrustedValidators == nil {
		return ufmt.Errorf("trusted validator set in Header2 cannot be empty")
	}
	if m.Header1.Header.ChainID != m.Header2.Header.ChainID {
		return ufmt.Errorf("headers must have identical chainIDs")
	}

	// ValidateBasic on both validators
	if err := m.Header1.ValidateBasic(); err != nil {
		return ufmt.Errorf("header 1 failed validation: %v", err)
	}
	if err := m.Header2.ValidateBasic(); err != nil {
		return ufmt.Errorf("header 2 failed validation: %v", err)
	}
	// Ensure that Height1 is greater than or equal to Height2
	if m.Header1.GetHeight().LT(m.Header2.GetHeight()) {
		return ufmt.Errorf("Header1 height is less than Header2 height (%s < %s)", m.Header1.GetHeight(), m.Header2.GetHeight())
	}

	if err := validateCommit(m.Header1); err != nil {
		return ufmt.Errorf("invalid header1 commit: %v", err)
	}
	if err := validateCommit(m.Header2); err != nil {
		return ufmt.Errorf("invalid header2 commit: %v", err)
	}
	return nil
}

// validateCommit checks if the given commit is a valid commit from the
// passed-in MsgHeader.
func validateCommit(msg *MsgHeader) error {
	votingPowerNeeded := msg.ValidatorSet.TotalVotingPower * 2 / 3
	if err := verifyCommit(msg.Header.ChainID, msg.ValidatorSet, msg.Commit, votingPowerNeeded, true); err != nil {
		return ufmt.Errorf("validator set did not commit to header: %v", err)
	}
	return nil
}

