func NewMsgHeader(chainID string, timestamp time.Time,
	apphash []byte, height uint64, trustedHeight types.Height,
	valset, nextValset, trustedValset *tendermint.ValidatorSet,
	signatures []tendermint.CommitSig) *tendermint.MsgHeader {
	header := &tendermint.Header{
		Version: tendermint.Consensus{
			Block: tendermint.BlockProtocol,
			App:   0,
		},
		ChainID: chainID,
		Height:  height,
		Time:    timestamp,
		LastBlockID: tendermint.BlockID{
			Hash: Hash("last_block_hash"),
			PartSetHeader: tendermint.PartSetHeader{
				Total: 1,
				Hash:  Hash("last_block_partset_hash"),
			},
		},
		LastCommitHash:     Hash("last_commit_hash"),
		DataHash:           Hash("data_hash"),
		ValidatorsHash:     valset.Hash(),
		NextValidatorsHash: nextValset.Hash(),
		ConsensusHash:      Hash("consensus_hash"),
		AppHash:            apphash,
		LastResultsHash:    Hash("last_results_hash"),
		EvidenceHash:       Hash("evidence_hash"),
		ProposerAddress:    valset.Validators[0].Address,
	}

	return &tendermint.MsgHeader{
		Header: header,
		Commit: &tendermint.Commit{
			Height: height,
			Round:  0,
			BlockID: tendermint.BlockID{
				Hash: header.Hash(), // compute expected block hash
				PartSetHeader: tendermint.PartSetHeader{
					Total: 1,
					Hash:  Hash("block_partset_hash"),
				},
			},
			Signatures: signatures,
		},
		ValidatorSet:      valset,
		TrustedHeight:     trustedHeight,
		TrustedValidators: trustedValset,
	}
}

func NewClientState(chainID string, height types.Height) tendermint.ClientState {
	return tendermint.ClientState{
		ChainID:         chainID,
		TrustLevel:      tendermint.DefaultTrustLevel,
		UnbondingPeriod: time.Hour * 3,
		TrustingPeriod:  time.Hour,
		MaxClockDrift:   time.Hour,
		LatestHeight:    height,
		ProofSpecs:      ics23.GetSDKProofSpecs(),
	}
}

func GenValset() *tendermint.ValidatorSet {
	var (
		val1 = &tendermint.Validator{
			Address:     GenAddr("val1"),
			PubKey:      GenPubkey("val1_pubkey"),
			VotingPower: 2,
		}
		val2 = &tendermint.Validator{
			Address:     GenAddr("val2"),
			PubKey:      GenPubkey("val2_pubkey"),
			VotingPower: 3,
		}
	)
	return tendermint.NewValset(val1, val2)
}

func GenConsensusState(timestamp time.Time, apphash, valsethash []byte) tendermint.ConsensusState {
	return tendermint.ConsensusState{
		Timestamp:          timestamp,
		Root:               tendermint.MerkleRoot{Hash: apphash},
		NextValidatorsHash: valsethash,
	}
}

func GenMsgHeader(chainID string, timestamp time.Time, apphash []byte,
	height uint64, trustedHeight types.Height,
	valset, nextValset, trustedValset *tendermint.ValidatorSet) *tendermint.MsgHeader {
	var (
		signatures = []tendermint.CommitSig{
			{
				BlockIDFlag:      tendermint.BlockIDFlagCommit,
				ValidatorAddress: valset.Validators[0].Address,
				Timestamp:        ToTime("2025-09-25T07:55:57.306746166Z"),
				Signature:        B64Dec("qtv1z4S2Q6T87vGQo0lrjRZqv9PrHIji4pTyviMnVyGx9td6eySdzwQwCthwmihU48ebNlFiMlFJ0CT891UmDg=="),
			},
			{
				BlockIDFlag:      tendermint.BlockIDFlagCommit,
				ValidatorAddress: valset.Validators[1].Address,
				Timestamp:        ToTime("2025-09-25T07:55:57.310583641Z"),
				Signature:        B64Dec("Q5E6Kjma00n/T98rC9qJmoB6JTGFX/IB+mDVs4Wd1h0eJ8fabY/6oI8zdoU6/7W6VR6wjpHyWBsJrpGT6C0LCg=="),
			},
		}
	)
	return NewMsgHeader(chainID, timestamp, apphash, height, trustedHeight,
		valset, nextValset, trustedValset, signatures)
}

func GenAddr(seed string) []byte {
	return Hash(seed)[:tendermint.AddressSize]
}

func GenSignature(seed string) []byte {
	h := Hash(seed)
	return append(h, Hash(string(h))...) // 32x2=64 bytes
}

func GenPubkey(seed string) []byte {
	return Hash(seed) //pubkey len is 32 bytes
}

func Hash(s string) []byte {
	bz := sha256.Sum256([]byte(s))
	return bz[:]
}

func B64Dec(s string) []byte {
	bz, err := base64.StdEncoding.DecodeString(s)
	if err != nil {
		panic(err)
	}
	return bz
}

func ToTime(s string) time.Time {
	t, err := time.Parse(time.RFC3339Nano, s)
	if err != nil {
		panic(err)
	}
	return t
}

// Package grc20test provides a test GRC20 token for IBC transfer testing.
package grc20test

import (
	"gno.land/p/demo/tokens/grc20"
	"gno.land/r/demo/defi/grc20reg"
)

// Slug is the grc20reg registration slug (the third argument to
// grc20reg.Register). Slugs must be alphanumeric (enforced by grc20reg).
const Slug = "TEST"

// Token, ledger, and UserTeller are initialised in init(cur realm) because
// grc20.NewToken now requires a `realm` capability and there is no realm
// value available at package-level var init time.
var (
	Token      *grc20.Token
	ledger     *grc20.PrivateLedger
	UserTeller grc20.Teller
)

func init(cur realm) {
	Token, ledger = grc20.NewToken("Test", "TEST", 0, 0, cur)
	UserTeller = Token.CallerTeller()
	grc20reg.Register(cross(cur), Token, Slug)
}

// Mint tokens to the specified address.
// WARNING: test-only, no caller authorization — do not use as a pattern for production.
func Mint(cur realm, to address, amount int64) {
	if err := ledger.Mint(to, amount); err != nil {
		panic(err)
	}
}

// Approve sets an allowance for spender to spend owner's tokens.
// Uses PrivateLedger directly to allow explicit owner specification.
// WARNING: test-only, no caller authorization — do not use as a pattern for production.
func Approve(cur realm, owner, spender address, amount int64) {
	if err := ledger.Approve(owner, spender, amount); err != nil {
		panic(err)
	}
}

func BalanceOf(addr address) int64 {
	return UserTeller.BalanceOf(addr)
}

func TotalSupply() int64 {
	return UserTeller.TotalSupply()
}

func Allowance(owner, spender address) int64 {
	return UserTeller.Allowance(owner, spender)
}

package testing

import (
	"gno.land/p/aib/ibc/app"
	"gno.land/p/aib/ibc/types"
	"gno.land/p/nt/ufmt/v0"
)

type (
	App struct {
		id    string
		Calls struct {
			OnSendPacket                  []Args
			OnSendPacketReturn            error
			OnRecvPacket                  []Args
			OnRecvPacketReturn            types.RecvPacketResult
			OnTimeoutPacket               []Args
			OnTimeoutPacketReturn         error
			OnAcknowledgementPacket       []Args
			OnAcknowledgementPacketReturn error
		}
	}
	Args struct {
		SourceClient      string
		DestinationClient string
		Sequence          uint64
		Payload           types.Payload
		Ack               []byte
	}
)

var (
	_    app.IBCApp = &App{}
	apps []*App
)

func NewApp(_ realm) *App {
	app := &App{}
	// store the app in the realm is required to prevent the following panic:
	// "cannot directly modify readonly tainted object (w/o method)"
	// Other than that it is not used.
	apps = append(apps, app)
	return app
}

// Implements app.IBCApp
func (a *App) OnSendPacket(
	_ realm,
	sourceClient string,
	destinationClient string,
	sequence uint64,
	payload types.Payload,
) error {
	a.Calls.OnSendPacket = append(a.Calls.OnSendPacket,
		Args{
			SourceClient:      sourceClient,
			DestinationClient: destinationClient,
			Sequence:          sequence,
			Payload:           payload,
		})
	return a.Calls.OnSendPacketReturn
}

func (a *App) SetOnSendPacketReturn(err error) {
	a.Calls.OnSendPacketReturn = err
}

// Implements app.IBCApp
func (a *App) OnRecvPacket(
	_ realm,
	sourceClient string,
	destinationClient string,
	sequence uint64,
	payload types.Payload,
) types.RecvPacketResult {
	a.Calls.OnRecvPacket = append(a.Calls.OnRecvPacket,
		Args{
			SourceClient:      sourceClient,
			DestinationClient: destinationClient,
			Sequence:          sequence,
			Payload:           payload,
		})
	// NOTE return a copy of the result to avoid annoying gno errors like
	// "illegal conversion of readonly or externally stored value"
	res := types.RecvPacketResult{
		Status:          a.Calls.OnRecvPacketReturn.Status,
		Acknowledgement: make([]byte, len(a.Calls.OnRecvPacketReturn.Acknowledgement)),
	}
	copy(res.Acknowledgement, a.Calls.OnRecvPacketReturn.Acknowledgement)
	return res
}

func (a *App) SetOnRecvPacketReturn(res types.RecvPacketResult) {
	a.Calls.OnRecvPacketReturn = res
}

// Implements app.IBCApp
func (a *App) OnTimeoutPacket(
	_ realm,
	sourceClient string,
	destinationClient string,
	sequence uint64,
	payload types.Payload,
) error {
	a.Calls.OnTimeoutPacket = append(a.Calls.OnTimeoutPacket,
		Args{
			SourceClient:      sourceClient,
			DestinationClient: destinationClient,
			Sequence:          sequence,
			Payload:           payload,
		})
	return a.Calls.OnTimeoutPacketReturn
}

// Implements app.IBCApp
func (a *App) OnAcknowledgementPacket(
	_ realm,
	sourceClient string,
	destinationClient string,
	sequence uint64,
	acknowledgement []byte,
	payload types.Payload,
) error {
	a.Calls.OnAcknowledgementPacket = append(a.Calls.OnAcknowledgementPacket,
		Args{
			SourceClient:      sourceClient,
			DestinationClient: destinationClient,
			Sequence:          sequence,
			Payload:           payload,
			Ack:               acknowledgement,
		})
	return a.Calls.OnAcknowledgementPacketReturn
}

func (a *App) Report() string {
	var s string
	s += ufmt.Sprintf("OnSendPacket (%d)\n", len(a.Calls.OnSendPacket))
	for _, args := range a.Calls.OnSendPacket {
		s += args.Report() + "\n"
	}
	s += ufmt.Sprintf("OnRecvPacket (%d)\n", len(a.Calls.OnRecvPacket))
	for _, args := range a.Calls.OnRecvPacket {
		s += args.Report() + "\n"
	}
	s += ufmt.Sprintf("OnTimeoutPacket (%d)\n", len(a.Calls.OnTimeoutPacket))
	for _, args := range a.Calls.OnTimeoutPacket {
		s += args.Report() + "\n"
	}
	s += ufmt.Sprintf("OnAcknowledgementPacket (%d)\n", len(a.Calls.OnAcknowledgementPacket))
	for _, args := range a.Calls.OnAcknowledgementPacket {
		s += args.Report() + "\n"
	}
	return s
}

func (a *Args) Report() string {
	var s string
	s += ufmt.Sprintf("- sourceClient: %s\n", a.SourceClient)
	s += ufmt.Sprintf("- destinationClient: %s\n", a.DestinationClient)
	s += ufmt.Sprintf("- sequence: %d\n", a.Sequence)
	s += "- payload:\n"
	s += ufmt.Sprintf("  - sourcePort: %s\n", a.Payload.SourcePort)
	s += ufmt.Sprintf("  - destinationPort: %s\n", a.Payload.DestinationPort)
	s += ufmt.Sprintf("  - version: %s\n", a.Payload.Version)
	s += ufmt.Sprintf("  - encoding: %s\n", a.Payload.Encoding)
	s += ufmt.Sprintf("  - value: %s\n", string(a.Payload.Value))
	if len(a.Ack) > 0 {
		s += ufmt.Sprintf("- ack: %s\n", string(a.Ack))
	}
	return s
}

