package core

import (
	"chain/runtime/unsafe"

	"gno.land/p/nt/bptree/v0"
	"gno.land/p/nt/ufmt/v0"
)

var (
	admin    address
	relayers = bptree.NewBPTree32()
)

func init() {
	// Set admin to the deployer's EOA. In production this is non-empty.
	// In the gno test framework the base store is pre-loaded with
	// OriginCaller="" so admin stays empty; SetAdmin then acts as bootstrap.
	admin = unsafe.OriginCaller()
}

// SetAdmin sets or transfers the admin role.
// If no admin is currently set (admin was not initialized in init, e.g. in
// tests), the first caller becomes admin. Once set, only the current admin
// can change it.
func SetAdmin(cur realm, newAdmin address) {
	if admin != "" {
		ensureAdminCaller()
	}
	admin = newAdmin
}

// AddRelayer adds an address to the authorized relayer whitelist.
// Can only be called by the admin.
func AddRelayer(cur realm, addr address) {
	ensureAdminCaller()
	relayers.Set(string(addr), true)
}

// RemoveRelayer removes an address from the authorized relayer whitelist.
// Can only be called by the admin.
func RemoveRelayer(cur realm, addr address) {
	ensureAdminCaller()
	relayers.Remove(string(addr))
}

// ensureAdminCaller panics if the EOA that signed the tx is not the admin.
// Uses unsafe.OriginCaller for tx-level EOA identity — admin authority is
// intentionally bound to the EOA that submitted the tx, which has no cur
// equivalent (cur.Previous() identifies the immediate frame, not the
// signer). Mirrors the v2 admin pattern in r/gnoland/blog/admin.gno.
//
// Trade-off: this allows the admin EOA to authorize admin ops through any
// intermediate realm (e.g. via maketx run, or a wrapper realm). That is
// the same tx.origin risk class as `runtime.OriginCaller` in v1; callers
// who set admin to an EOA must ensure that EOA does not call into
// untrusted code in the same tx.
func ensureAdminCaller() {
	caller := unsafe.OriginCaller()
	if caller != admin {
		panic(ufmt.Sprintf("unauthorized: caller %s is not the admin", caller))
	}
}

// ensureAuthorizedRelayer panics if the EOA that signed the tx is not in the
// relayer whitelist. If the whitelist is empty any EOA is allowed. Returns
// the relayer's EOA address. Same EOA-binding rationale as ensureAdminCaller.
func ensureAuthorizedRelayer() address {
	caller := unsafe.OriginCaller()
	if relayers.Size() == 0 {
		return caller
	}
	if !relayers.Has(string(caller)) {
		panic(ufmt.Sprintf("unauthorized relayer %s", caller))
	}
	return caller
}

package core

import (
	"gno.land/p/aib/ibc/app"
	"gno.land/p/aib/ibc/host"
	"gno.land/p/nt/ufmt/v0"
)

// RegisterApp registers an IBCApp, the portID is determined using the package
// path of the caller, hence it must an other realm.
func RegisterApp(cur realm, portID string, app app.IBCApp) {
	caller := cur.Previous()
	if caller.IsUser() {
		panic("RegisterApp can only be called from an other realm")
	}
	if err := host.PortIdentifierValidator(portID); err != nil {
		panic(ufmt.Errorf("invalid portID: %v", err))
	}
	if _, ok := store.routes[portID]; ok {
		panic(ufmt.Errorf("portID %s has already been registered", portID))
	}
	store.routes[portID] = ibcApp{
		IBCApp:  app,
		pkgPath: caller.PkgPath(),
		address: caller.Address(),
	}
}

package core

import (
	"chain"
	"chain/runtime/unsafe"

	"gno.land/p/aib/ibc/host"
	"gno.land/p/aib/ibc/lightclient"
	"gno.land/p/aib/ibc/types"
	"gno.land/p/nt/ufmt/v0"
)

// CreateClient generates a new client identifier and invokes the associated
// light client module in order to initialize the client.
func CreateClient(cur realm, clientState lightclient.ClientState, consensusState lightclient.ConsensusState) string {
	if clientState.ClientType() != consensusState.ClientType() {
		panic("client type for client state and consensus state do not match")
	}
	if err := types.ValidateClientType(clientState.ClientType()); err != nil {
		panic(ufmt.Sprintf(
			"client type does not meet naming constraints: %v", err,
		))
	}

	if err := clientState.ValidateBasic(); err != nil {
		panic(err)
	}
	if err := consensusState.ValidateBasic(); err != nil {
		panic(err)
	}
	relayer := ensureAuthorizedRelayer()
	c := store.addClient(clientState.ClientType(), relayer)
	err := c.lightClient.Initialize(clientState, consensusState)
	if err != nil {
		panic(err)
	}
	if status := c.lightClient.Status(); status != lightclient.Active {
		panic(ufmt.Sprintf("cannot create client (%s) with status %s", c.id, status))
	}
	// Emit create client event
	chain.Emit(types.EventTypeCreateClient,
		types.AttributeKeyClientID, c.id,
		types.AttributeKeyClientType, c.typ,
		types.AttributeKeyConsensusHeights, c.lightClient.LatestHeight().String(),
	)
	return c.id
}

// ClientIDs returns the list of known client identifiers, sorted lexically by
// id (the underlying b+tree order). Intended for read-only callers (UIs,
// other realms building txlinks).
func ClientIDs() []string {
	ids := make([]string, 0, store.clientByID.Size())
	store.clientByID.IterateByOffset(0, store.clientByID.Size(), func(k string, _ any) bool {
		ids = append(ids, k)
		return false
	})
	return ids
}

// ClientLatestHeight returns the latest (highest) consensus height the given
// client has been updated to, formatted as "<revision>/<height>". This is the
// client's latest trusted height. Returns "" if the client is unknown.
// Intended for read-only callers (UIs) that want to surface how up-to-date a
// client is.
func ClientLatestHeight(clientID string) string {
	c := store.getClient(clientID)
	if c == nil {
		return ""
	}
	return c.lightClient.LatestHeight().String()
}

// ClientStatus returns the status of the given client (Active, Expired,
// Frozen, ...). Returns "" if the client is unknown. Intended for read-only
// callers (UIs) that want to surface whether a client is usable.
func ClientStatus(clientID string) string {
	c := store.getClient(clientID)
	if c == nil {
		return ""
	}
	return c.lightClient.Status()
}

// RegisterCounterparty will register the IBC v2 counterparty info for the
// given clientID. It must be called by the same relayer that called
// CreateClient.
func RegisterCounterparty(cur realm, clientID string, counterpartyMerklePrefix [][]byte, counterpartyClientID string) {
	if !types.IsValidClientID(counterpartyClientID) {
		panic("invalid counterparty client id")
	}
	c := store.getClient(clientID)
	if c == nil {
		panic(ufmt.Sprintf("client %s not found", clientID))
	}
	caller := unsafe.OriginCaller()
	if c.creator != caller {
		panic(ufmt.Sprintf("expected same signer as CreateClient submitter %s, got %s", c.creator, caller))
	}
	if c.counterpartyClientID != "" {
		panic("cannot register counterparty once it is already set")
	}
	c.counterpartyClientID = counterpartyClientID
	c.counterpartyMerklePrefix = counterpartyMerklePrefix
}

// UpdateClient will update the given IBC v2 light client with a new header.
// Can also be used to submit a misbehavior (clientMessage can be a header or
// a misbehavior, maybe split into 2 functions would make more sense here).
func UpdateClient(cur realm, clientID string, clientMessage lightclient.ClientMessage) {
	if err := clientMessage.ValidateBasic(); err != nil {
		panic(err)
	}
	c := store.getClient(clientID)
	if c == nil {
		panic(ufmt.Sprintf("client %s not found", clientID))
	}
	ensureAuthorizedRelayer()
	if c.typ != clientMessage.ClientType() {
		panic("client type for client state and client message do not match")
	}
	if status := c.lightClient.Status(); status != lightclient.Active {
		panic(ufmt.Sprintf("cannot update client (%s) with status %s", c.id, status))
	}

	err := c.lightClient.VerifyClientMessage(clientMessage)
	if err != nil {
		panic(err)
	}

	foundMisbehavior := c.lightClient.CheckForMisbehaviour(clientMessage)
	if foundMisbehavior {
		c.lightClient.UpdateStateOnMisbehaviour(clientMessage)

		chain.Emit(types.EventTypeSubmitMisbehaviour,
			types.AttributeKeyClientID, c.id,
			types.AttributeKeyClientType, c.typ,
		)
		return
	}

	consensusHeights := c.lightClient.UpdateState(clientMessage)

	// Emit update client event
	var consensusHeightsStr string
	for i, h := range consensusHeights {
		consensusHeightsStr += h.String()
		if i < len(consensusHeights)-1 {
			consensusHeightsStr += ", "
		}
	}
	chain.Emit(types.EventTypeUpdateClient,
		types.AttributeKeyClientID, c.id,
		types.AttributeKeyClientType, c.typ,
		types.AttributeKeyConsensusHeights, consensusHeightsStr,
	)
}

// UpgradeClient upgrades the client to a new client and consensus state,
// verified by proofs that the counterparty chain committed to those states
// at its UpgradePath under the current client's latest consensus root.
func UpgradeClient(cur realm, clientID string, clientState, consensusState, proofUpgradeClient, proofUpgradeConsensusState any) {
	if err := host.ClientIdentifierValidator(clientID); err != nil {
		panic(err)
	}
	ensureAuthorizedRelayer()
	c := store.getClient(clientID)
	if c == nil {
		panic(ufmt.Sprintf("client %s not found", clientID))
	}
	if status := c.lightClient.Status(); status != lightclient.Active {
		panic(ufmt.Sprintf("cannot upgrade client (%s) with status %s", c.id, status))
	}
	if err := c.lightClient.VerifyUpgradeAndUpdateState(clientState, consensusState, proofUpgradeClient, proofUpgradeConsensusState); err != nil {
		panic(err)
	}
	chain.Emit(types.EventTypeUpgradeClient,
		types.AttributeKeyClientID, c.id,
		types.AttributeKeyClientType, c.typ,
		types.AttributeKeyConsensusHeight, c.lightClient.LatestHeight().String(),
	)
}

// RecoverClient recovers a frozen or expired subject client using a healthy
// substitute client that tracks the same counterparty chain.
func RecoverClient(cur realm, subjectClientID, substituteClientID string) {
	ensureAdminCaller()
	if subjectClientID == substituteClientID {
		panic("subject and substitute client IDs must differ")
	}
	subject := store.getClient(subjectClientID)
	if subject == nil {
		panic(ufmt.Sprintf("subject client %s not found", subjectClientID))
	}
	substitute := store.getClient(substituteClientID)
	if substitute == nil {
		panic(ufmt.Sprintf("substitute client %s not found", substituteClientID))
	}
	if subject.typ != substitute.typ {
		panic(ufmt.Sprintf(
			"subject client type %s does not match substitute client type %s",
			subject.typ, substitute.typ,
		))
	}
	if status := subject.lightClient.Status(); status != lightclient.Frozen && status != lightclient.Expired {
		panic(ufmt.Sprintf(
			"cannot recover subject client %s with status %s",
			subject.id, status,
		))
	}
	if status := substitute.lightClient.Status(); status != lightclient.Active {
		panic(ufmt.Sprintf(
			"substitute client %s must be Active, got %s",
			substitute.id, status,
		))
	}
	if err := subject.lightClient.RecoverClient(substitute.lightClient); err != nil {
		panic(err)
	}
	chain.Emit(types.EventTypeRecoverClient,
		types.AttributeKeySubjectClientID, subject.id,
		types.AttributeKeySubstituteClientID, substitute.id,
		types.AttributeKeyClientType, subject.typ,
	)
}

package core

import (
	"bytes"
	"chain"
	"encoding/hex"
	"time"

	"gno.land/p/aib/ibc/host"
	"gno.land/p/aib/ibc/lightclient"
	"gno.land/p/aib/ibc/types"
	"gno.land/p/nt/ufmt/v0"
)

const maxTimeoutDelta time.Duration = 24 * time.Hour

func SendPacket(cur realm, msg types.MsgSendPacket) (sequence uint64) {
	if err := msg.ValidateBasic(); err != nil {
		panic(err)
	}
	clientID := msg.SourceClient
	c := store.getClient(clientID)
	if c == nil {
		panic(ufmt.Sprintf("client %s not found", clientID))
	}
	if status := c.lightClient.Status(); status != lightclient.Active {
		panic(ufmt.Sprintf("client (%s) status is %s", clientID, status))
	}

	// Ensure counterparty has been registered
	if c.counterpartyClientID == "" {
		panic(ufmt.Sprintf("counterparty not found for client %s", clientID))
	}

	// timeoutTimestamp must be greater than current block time and less or equal
	// to current block time + maxTimeoutDelta.
	var (
		timeout    = time.Unix(int64(msg.TimeoutTimestamp), 0)
		minTimeout = time.Now()
		maxTimeout = minTimeout.Add(maxTimeoutDelta)
	)
	if !timeout.After(minTimeout) {
		panic(ufmt.Sprintf(
			"timeout is less than or equal the current block timestamp, %d <= %d",
			msg.TimeoutTimestamp, minTimeout.Unix(),
		))
	}
	if timeout.After(maxTimeout) {
		panic(ufmt.Sprintf(
			"timeout is after the max allowed timeout, %d > %d",
			msg.TimeoutTimestamp, maxTimeout.Unix(),
		))
	}

	// check if the latest consensus timestamp is lower than timeoutTimestamp
	latestTimestamp, err := c.lightClient.TimestampAtHeight(c.lightClient.LatestHeight())
	if err != nil {
		panic(err)
	}
	if latestTimestamp >= msg.TimeoutTimestamp {
		panic(ufmt.Errorf("latest timestamp: %d, timeout timestamp: %d",
			latestTimestamp, msg.TimeoutTimestamp))
	}

	// construct packet from given fields
	sequence = uint64(c.sendSeq.Next())
	packet := types.NewPacket(sequence, msg.SourceClient, c.counterpartyClientID, msg.TimeoutTimestamp, msg.Payloads...)
	if err := packet.ValidateBasic(); err != nil {
		panic(ufmt.Errorf("constructed packet failed basic validation: %v", err))
	}

	// set the packet commitment
	c.setPacketCommitment(sequence, packet)

	// emit events
	chain.Emit(types.EventTypeSendPacket,
		types.AttributeKeySrcClient, packet.SourceClient,
		types.AttributeKeyDstClient, packet.DestinationClient,
		types.AttributeKeySequence, ufmt.Sprintf("%d", packet.Sequence),
		types.AttributeKeyTimeoutTimestamp, ufmt.Sprintf("%d", packet.TimeoutTimestamp),
		types.AttributeKeyEncodedPacketHex, hex.EncodeToString(packet.ProtoMarshal()),
	)

	// Invoke registed app OnSendPacket() for each payload.SourcePort.
	for i, payload := range msg.Payloads {
		app := store.route(payload.SourcePort)
		err := app.OnSendPacket(
			cross(cur), msg.SourceClient, c.counterpartyClientID, sequence, payload,
		)
		if err != nil {
			panic(ufmt.Sprintf(
				"send packet failed for payload #%d app %q: %v", i, payload.SourcePort, err,
			))
		}
	}

	return sequence
}

func RecvPacket(cur realm, msg types.MsgRecvPacket) types.ResponseResultType {
	if err := msg.ValidateBasic(); err != nil {
		panic(err)
	}

	clientID := msg.Packet.DestinationClient
	c := store.getClient(clientID)
	if c == nil {
		panic(ufmt.Sprintf("client %s not found", clientID))
	}
	ensureAuthorizedRelayer()
	// check client is active
	if status := c.lightClient.Status(); status != lightclient.Active {
		panic(ufmt.Sprintf("client (%s) status is %s", clientID, status))
	}
	// check counterparty
	if c.counterpartyClientID != msg.Packet.SourceClient {
		panic(ufmt.Sprintf(
			"counterparty id (%s) does not match packet source id (%s)",
			c.counterpartyClientID, msg.Packet.SourceClient,
		))
	}
	currentTimestamp := uint64(time.Now().Unix())
	if currentTimestamp >= msg.Packet.TimeoutTimestamp {
		panic(ufmt.Sprintf(
			"current timestamp: %d, timeout timestamp: %d",
			currentTimestamp, msg.Packet.TimeoutTimestamp,
		))
	}

	// REPLAY PROTECTION: Packet receipts will indicate that a packet has already
	// been received.
	// Packet receipts must not be pruned, unless it has been marked stale by the
	// increase of the recvStartSequence. TODO check relevancy of comment
	if c.hasPacketReceipt(msg.Packet.Sequence) {
		// This error indicates that the packet has already been relayed. Core IBC
		// will treat this error as a no-op in order to prevent an entire relay
		// transaction from failing and consuming unnecessary fees.
		return types.RESPONSE_NOOP
	}

	// Verify existence of the commitment bytes in the proofs.
	var (
		key        = host.PacketCommitmentKey(msg.Packet.SourceClient, msg.Packet.Sequence)
		merklePath = types.BuildMerklePath(c.counterpartyMerklePrefix, key)
		value      = types.CommitPacket(msg.Packet)
	)
	if err := c.lightClient.VerifyMembership(
		msg.ProofHeight, msg.ProofCommitment, merklePath, value,
	); err != nil {
		panic(ufmt.Sprintf(
			"failed packet commitment verification for client (%s): %v",
			clientID, err,
		))
	}

	// Set Packet Receipt to prevent timeout from occurring on counterparty
	c.setPacketReceipt(msg.Packet.Sequence)

	// Emit events
	chain.Emit(types.EventTypeRecvPacket,
		types.AttributeKeySrcClient, msg.Packet.SourceClient,
		types.AttributeKeyDstClient, msg.Packet.DestinationClient,
		types.AttributeKeySequence, ufmt.Sprintf("%d", msg.Packet.Sequence),
		types.AttributeKeyTimeoutTimestamp, ufmt.Sprintf("%d", msg.Packet.TimeoutTimestamp),
		types.AttributeKeyEncodedPacketHex, hex.EncodeToString(msg.Packet.ProtoMarshal()),
	)

	c.writeRecvPacketAcknowledgement(0, cur, msg.Packet)

	return types.RESPONSE_SUCCESS
}

// writeRecvPacketAcknowledgement is a non-crossing helper: rlm is the caller's
// live cur, threaded as a non-first param via the `_ int, rlm realm` shape so
// the cross to each app's OnRecvPacket can be issued from RecvPacket's frame.
func (c *client) writeRecvPacketAcknowledgement(_ int, rlm realm, packet types.Packet) {
	var (
		// build up the recv results for each application callback.
		ack = types.Acknowledgement{
			AppAcknowledgements: [][]byte{},
		}
		isSuccess = true
	)

	// Invoke registed app OnRecvPacket() for each payload.DestinationPort.
	for i, payload := range packet.Payloads {
		app := store.route(payload.DestinationPort)
		res := app.OnRecvPacket(
			cross(rlm), packet.SourceClient, packet.DestinationClient,
			packet.Sequence, payload,
		)
		if res.Status == types.PacketStatus_Failure {
			isSuccess = false
			// construct acknowledgement with single app acknowledgement that is the
			// sentinel error acknowledgement
			ack = types.Acknowledgement{
				AppAcknowledgements: [][]byte{types.UniversalErrorAcknowledgement()},
			}
			break
		}
		if res.Status == types.PacketStatus_Async {
			if len(packet.Payloads) > 1 {
				panic("async ack not supported for multi-payload packets")
			}
			c.savePendingAsyncAck(packet, app.pkgPath)
			return
		}

		// successful app acknowledgement cannot equal sentinel error
		// acknowledgement
		if bytes.Equal(res.Acknowledgement, types.UniversalErrorAcknowledgement()) {
			panic(ufmt.Sprintf(
				"callback error for payload #%d app %q: application acknowledgement cannot be sentinel error acknowledgement",
				i, payload.DestinationPort,
			))
		}

		// append app acknowledgement to the overall acknowledgement
		ack.AppAcknowledgements = append(ack.AppAcknowledgements, res.Acknowledgement)
	}

	// Sanity check to ensure returned acknowledgement and calculated isSuccess
	// boolean matches
	if ack.Success() != isSuccess {
		panic("acknowledgement success flag mismatch")
	}
	if err := ack.Validate(); err != nil {
		panic(err)
	}
	// set the acknowledgement so that it can be verified on the other side
	c.setPacketAcknowledgement(packet.Sequence, types.CommitAcknowledgement(ack))
	emitWriteAcknowledgement(packet, ack)
}

func WriteAcknowledgement(cur realm, clientID string, sequence uint64, ack types.Acknowledgement) {
	c := store.getClient(clientID)
	if c == nil {
		panic(ufmt.Sprintf("client %s not found", clientID))
	}

	pending, found := c.getPendingAsyncAck(sequence)
	if !found {
		panic(ufmt.Sprintf("no pending async ack for client=%s sequence=%d", clientID, sequence))
	}

	callerPath := cur.Previous().PkgPath()
	if callerPath != pending.appPkgPath {
		panic(ufmt.Sprintf(
			"caller %s is not authorized to write ack for sequence %d (expected %s)",
			callerPath, sequence, pending.appPkgPath,
		))
	}

	if c.hasPacketAcknowledgement(sequence) {
		panic(ufmt.Sprintf("acknowledgement already written for sequence %d", sequence))
	}
	if err := ack.Validate(); err != nil {
		panic(err)
	}

	c.setPacketAcknowledgement(sequence, types.CommitAcknowledgement(ack))
	c.deletePendingAsyncAck(sequence)
	emitWriteAcknowledgement(pending.packet, ack)
}

func emitWriteAcknowledgement(packet types.Packet, ack types.Acknowledgement) {
	chain.Emit(types.EventTypeWriteAck,
		types.AttributeKeySrcClient, packet.SourceClient,
		types.AttributeKeyDstClient, packet.DestinationClient,
		types.AttributeKeySequence, ufmt.Sprintf("%d", packet.Sequence),
		types.AttributeKeyTimeoutTimestamp, ufmt.Sprintf("%d", packet.TimeoutTimestamp),
		types.AttributeKeyEncodedPacketHex, hex.EncodeToString(packet.ProtoMarshal()),
		types.AttributeKeyEncodedAckHex, hex.EncodeToString(ack.ProtoMarshal()),
	)
}

func Acknowledgement(cur realm, msg types.MsgAcknowledgement) types.ResponseResultType {
	if err := msg.ValidateBasic(); err != nil {
		panic(err)
	}

	clientID := msg.Packet.SourceClient
	c := store.getClient(clientID)
	if c == nil {
		panic(ufmt.Sprintf("client %s not found", clientID))
	}
	ensureAuthorizedRelayer()
	// check client is active
	if status := c.lightClient.Status(); status != lightclient.Active {
		panic(ufmt.Sprintf("client (%s) status is %s", clientID, status))
	}
	// check counterparty
	if c.counterpartyClientID != msg.Packet.DestinationClient {
		panic(ufmt.Sprintf(
			"counterparty id (%s) does not match packet destination id (%s)",
			c.counterpartyClientID, msg.Packet.DestinationClient,
		))
	}

	commitment := c.getPacketCommitment(msg.Packet.Sequence)
	if len(commitment) == 0 {
		// This error indicates that the acknowledgement has already been relayed
		// or there is a misconfigured relayer attempting to prove an
		// acknowledgement for a packet never sent. Core IBC will treat this error
		// as a no-op in order to prevent an entire relay transaction from failing
		// and consuming unnecessary fees.
		return types.RESPONSE_NOOP
	}
	packetCommitment := types.CommitPacket(msg.Packet)
	// ensure integrity of commitment
	if !bytes.Equal(commitment, packetCommitment) {
		h1, h2 := hex.EncodeToString(packetCommitment), hex.EncodeToString(commitment)
		panic(ufmt.Sprintf(
			"commitment bytes are not equal: got (%v), expected (%v)", h1, h2,
		))
	}

	// Verify existence of the acknowledgement commitment bytes in the proofs.
	var (
		key        = host.PacketAcknowledgementKey(msg.Packet.DestinationClient, msg.Packet.Sequence)
		merklePath = types.BuildMerklePath(c.counterpartyMerklePrefix, key)
		value      = types.CommitAcknowledgement(msg.Acknowledgement)
	)
	if err := c.lightClient.VerifyMembership(
		msg.ProofHeight, msg.ProofAcked, merklePath, value,
	); err != nil {
		panic(ufmt.Sprintf(
			"failed packet acknowledgement verification for client (%s): %v",
			clientID, err,
		))
	}

	c.deletePacketCommitment(msg.Packet.Sequence)

	chain.Emit(types.EventTypeAcknowledgePacket,
		types.AttributeKeySrcClient, msg.Packet.SourceClient,
		types.AttributeKeyDstClient, msg.Packet.DestinationClient,
		types.AttributeKeySequence, ufmt.Sprintf("%d", msg.Packet.Sequence),
		types.AttributeKeyTimeoutTimestamp, ufmt.Sprintf("%d", msg.Packet.TimeoutTimestamp),
		types.AttributeKeyEncodedPacketHex, hex.EncodeToString(msg.Packet.ProtoMarshal()),
	)

	// Invoke registed app OnAcknowledgementPacket() for each payload.SourcePort.
	recvSuccess := !bytes.Equal(msg.Acknowledgement.AppAcknowledgements[0],
		types.UniversalErrorAcknowledgement())
	for i, payload := range msg.Packet.Payloads {
		app := store.route(payload.SourcePort)
		// if recv was successful, each payload should have its own acknowledgement
		// so we send each individual acknowledgment to the application otherwise,
		// the acknowledgement only contains the sentinel error acknowledgement
		// which we send to the application. The application is responsible for
		// knowing that this is an error acknowledgement and executing the
		// appropriate logic.
		var ack []byte
		if recvSuccess {
			ack = msg.Acknowledgement.AppAcknowledgements[i]
		} else {
			ack = types.UniversalErrorAcknowledgement()
		}
		err := app.OnAcknowledgementPacket(
			cross(cur), msg.Packet.SourceClient, msg.Packet.DestinationClient,
			msg.Packet.Sequence, ack, payload,
		)
		if err != nil {
			panic(ufmt.Sprintf(
				"acknowledgement packet failed for payload #%d app %q: %v",
				i, payload.SourcePort, err,
			))
		}
	}

	return types.RESPONSE_SUCCESS
}

func Timeout(cur realm, msg types.MsgTimeout) types.ResponseResultType {
	if err := msg.ValidateBasic(); err != nil {
		panic(err)
	}

	clientID := msg.Packet.SourceClient
	c := store.getClient(clientID)
	if c == nil {
		panic(ufmt.Sprintf("client %s not found", clientID))
	}
	ensureAuthorizedRelayer()
	// check client is active
	if status := c.lightClient.Status(); status != lightclient.Active {
		panic(ufmt.Sprintf("client (%s) status is %s", clientID, status))
	}
	// check counterparty
	if c.counterpartyClientID != msg.Packet.DestinationClient {
		panic(ufmt.Sprintf(
			"counterparty id (%s) does not match packet destination id (%s)",
			c.counterpartyClientID, msg.Packet.DestinationClient,
		))
	}
	// check that timeout timestamp has passed on the other end
	proofTimestamp, err := c.lightClient.TimestampAtHeight(msg.ProofHeight)
	if err != nil {
		panic(err)
	}
	if proofTimestamp < msg.Packet.TimeoutTimestamp {
		panic(ufmt.Errorf("proof timestamp: %d, timeout timestamp: %d",
			proofTimestamp, msg.Packet.TimeoutTimestamp))
	}

	commitment := c.getPacketCommitment(msg.Packet.Sequence)
	if len(commitment) == 0 {
		// This error indicates that the timeout has already been relayed or there
		// is a misconfigured relayer attempting to prove a timeout for a packet
		// never sent. Core IBC will treat this error as a no-op in order to
		// prevent an entire relay transaction from failing and consuming
		// unnecessary fees.
		return types.RESPONSE_NOOP
	}
	packetCommitment := types.CommitPacket(msg.Packet)
	// ensure integrity of commitment
	if !bytes.Equal(commitment, packetCommitment) {
		h1, h2 := hex.EncodeToString(packetCommitment), hex.EncodeToString(commitment)
		panic(ufmt.Sprintf(
			"commitment bytes are not equal: got (%v), expected (%v)", h1, h2,
		))
	}

	// Verify packet receipt absence
	var (
		key        = host.PacketReceiptKey(msg.Packet.DestinationClient, msg.Packet.Sequence)
		merklePath = types.BuildMerklePath(c.counterpartyMerklePrefix, key)
	)
	if err := c.lightClient.VerifyNonMembership(
		msg.ProofHeight, msg.ProofUnreceived, merklePath,
	); err != nil {
		panic(ufmt.Sprintf(
			"failed packet receipt absence verification for client (%s): %v",
			clientID, err,
		))
	}

	c.deletePacketCommitment(msg.Packet.Sequence)

	chain.Emit(types.EventTypeTimeoutPacket,
		types.AttributeKeySrcClient, msg.Packet.SourceClient,
		types.AttributeKeyDstClient, msg.Packet.DestinationClient,
		types.AttributeKeySequence, ufmt.Sprintf("%d", msg.Packet.Sequence),
		types.AttributeKeyTimeoutTimestamp, ufmt.Sprintf("%d", msg.Packet.TimeoutTimestamp),
		types.AttributeKeyEncodedPacketHex, hex.EncodeToString(msg.Packet.ProtoMarshal()),
	)

	for i, payload := range msg.Packet.Payloads {
		app := store.route(payload.SourcePort)
		err := app.OnTimeoutPacket(
			cross(cur), msg.Packet.SourceClient, msg.Packet.DestinationClient,
			msg.Packet.Sequence, payload,
		)
		if err != nil {
			panic(ufmt.Sprintf(
				"timeout packet failed for payload #%d app %q: %v",
				i, payload.SourcePort, err,
			))
		}
	}

	return types.RESPONSE_SUCCESS
}

package core

import (
	"bytes"
	"testing"

	"gno.land/p/aib/ibc/lightclient"
	"gno.land/p/aib/ibc/types"
	"gno.land/p/nt/uassert/v0"
)

const asyncAckTestCallerPath = "gno.land/r/aib/ibc/core"

func TestWriteAcknowledgementSuccess(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	ack := newAsyncAckTestAck()

	c.savePendingAsyncAck(packet, asyncAckTestCallerPath)

	WriteAcknowledgement(cross(cur), c.id, packet.Sequence, ack)

	uassert.False(t, c.hasPendingAsyncAck(packet.Sequence))
	uassert.True(t, c.hasPacketAcknowledgement(packet.Sequence))
	if !bytes.Equal(types.CommitAcknowledgement(ack), c.getPacketAcknowledgement(packet.Sequence)) {
		t.Fatal("unexpected acknowledgement commitment")
	}
}

func TestWriteAcknowledgementWithoutAsyncRejected(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()

	uassert.AbortsContains(t, cur, "no pending async ack", func() {
		WriteAcknowledgement(cross(cur), c.id, 1, newAsyncAckTestAck())
	})
}

func TestWriteAcknowledgementWrongCallerPreservesPending(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	c.savePendingAsyncAck(packet, "gno.land/r/aib/ibc/not-the-caller")

	uassert.AbortsContains(t, cur, "is not authorized to write ack", func() {
		WriteAcknowledgement(cross(cur), c.id, packet.Sequence, newAsyncAckTestAck())
	})

	uassert.True(t, c.hasPendingAsyncAck(packet.Sequence))
	uassert.False(t, c.hasPacketAcknowledgement(packet.Sequence))
}

func TestWriteAcknowledgementDuplicateRejected(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	c.savePendingAsyncAck(packet, asyncAckTestCallerPath)

	WriteAcknowledgement(cross(cur), c.id, packet.Sequence, newAsyncAckTestAck())

	uassert.AbortsContains(t, cur, "no pending async ack", func() {
		WriteAcknowledgement(cross(cur), c.id, packet.Sequence, newAsyncAckTestAck())
	})
}

func TestWriteAcknowledgementAlreadyAckedRejected(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	ack := newAsyncAckTestAck()
	c.savePendingAsyncAck(packet, asyncAckTestCallerPath)
	c.setPacketAcknowledgement(packet.Sequence, types.CommitAcknowledgement(ack))

	uassert.AbortsContains(t, cur, "acknowledgement already written", func() {
		WriteAcknowledgement(cross(cur), c.id, packet.Sequence, ack)
	})

	uassert.True(t, c.hasPendingAsyncAck(packet.Sequence))
}

func TestPendingAsyncAckStoreRoundTrip(t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 7)

	c.savePendingAsyncAck(packet, asyncAckTestCallerPath)

	pending, found := c.getPendingAsyncAck(packet.Sequence)
	uassert.True(t, found)
	uassert.Equal(t, asyncAckTestCallerPath, pending.appPkgPath)
	uassert.Equal(t, packet.Sequence, pending.packet.Sequence)
	uassert.Equal(t, packet.SourceClient, pending.packet.SourceClient)
	uassert.Equal(t, packet.DestinationClient, pending.packet.DestinationClient)

	c.deletePendingAsyncAck(packet.Sequence)
	uassert.False(t, c.hasPendingAsyncAck(packet.Sequence))
}

func TestRecvPacketAsyncDefersAck(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	store.routes["appID"] = ibcApp{
		IBCApp: &asyncAckTestApp{res: types.RecvPacketResult{
			Status: types.PacketStatus_Async,
		}},
		pkgPath: asyncAckTestCallerPath,
	}

	c.writeRecvPacketAcknowledgement(0, cur, packet)

	uassert.True(t, c.hasPendingAsyncAck(packet.Sequence))
	uassert.False(t, c.hasPacketAcknowledgement(packet.Sequence))
}

func TestRecvPacketMultiPayloadAsyncRejected(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	packet.Payloads = append(packet.Payloads, packet.Payloads[0])
	store.routes["appID"] = ibcApp{
		IBCApp: &asyncAckTestApp{res: types.RecvPacketResult{
			Status: types.PacketStatus_Async,
		}},
		pkgPath: asyncAckTestCallerPath,
	}

	uassert.PanicsContains(t, cur, "async ack not supported for multi-payload packets", func() {
		c.writeRecvPacketAcknowledgement(0, cur, packet)
	})
}

func TestRecvPacketSuccessWritesAck(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	ack := []byte{0x02}
	store.routes["appID"] = ibcApp{
		IBCApp: &asyncAckTestApp{res: types.RecvPacketResult{
			Status:          types.PacketStatus_Success,
			Acknowledgement: ack,
		}},
		pkgPath: asyncAckTestCallerPath,
	}

	c.writeRecvPacketAcknowledgement(0, cur, packet)

	uassert.False(t, c.hasPendingAsyncAck(packet.Sequence))
	uassert.True(t, c.hasPacketAcknowledgement(packet.Sequence))
}

func TestSavePendingAsyncAckRejectsDuplicate(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	c.savePendingAsyncAck(packet, asyncAckTestCallerPath)

	uassert.PanicsContains(t, cur, "pending async ack already exists", func() {
		c.savePendingAsyncAck(packet, asyncAckTestCallerPath)
	})
}

func TestSavePendingAsyncAckRejectsAlreadyAcked(cur realm, t *testing.T) {
	c := newAsyncAckTestClient()
	packet := newAsyncAckTestPacket(c.id, 1)
	ack := newAsyncAckTestAck()
	c.setPacketAcknowledgement(packet.Sequence, types.CommitAcknowledgement(ack))

	uassert.PanicsContains(t, cur, "acknowledgement already written", func() {
		c.savePendingAsyncAck(packet, asyncAckTestCallerPath)
	})
}

func newAsyncAckTestClient() *client {
	store = newStore()
	c := store.addClient(lightclient.Tendermint, address("g1jg8mtutu9khhfwc4nxmuhcpftf0pajdhfvsqf5"))
	c.counterpartyClientID = "07-tendermint-42"
	return c
}

func newAsyncAckTestPacket(destinationClient string, sequence uint64) types.Packet {
	return types.Packet{
		Sequence:          sequence,
		SourceClient:      "07-tendermint-42",
		DestinationClient: destinationClient,
		TimeoutTimestamp:  1234567890,
		Payloads: []types.Payload{{
			SourcePort:      "appID",
			DestinationPort: "appID",
			Version:         "v1",
			Encoding:        "application/json",
			Value:           []byte("{}"),
		}},
	}
}

func newAsyncAckTestAck() types.Acknowledgement {
	return types.Acknowledgement{
		AppAcknowledgements: [][]byte{{0x01}},
