func renderCommitment(w *mux.ResponseWriter, r *mux.Request, tree *bptree.BPTree) {
	seqStr := r.GetVar("sequence")
	seq, err := strconv.ParseUint(seqStr, 10, 64)
	if err != nil {
		renderNode(w, nodeError("invalid sequence %q: %v", seqStr, err))
		return
	}
	v := tree.Get(seqid.ID(seq).Binary())
	if v == nil {
		renderNode(w, nodeError("sequence %s not found", seqStr))
		return
	}
	renderNode(w, commitmentNode(seq, v.([]byte)))
}

func renderCommitments(w *mux.ResponseWriter, r *mux.Request, tree *bptree.BPTree) {
	renderNode(w, jsonpage.Render(tree, r, func(k string, v any) *json.Node {
		id, _ := seqid.FromBinary(k)
		return commitmentNode(uint64(id), v.([]byte))
	}))
}

func commitmentNode(sequence uint64, data []byte) *json.Node {
	return json.ObjectNode("", map[string]*json.Node{
		"sequence": json.StringNode("", strconv.FormatUint(sequence, 10)),
		"data":     json.StringNode("", base64.StdEncoding.EncodeToString(data)),
	})
}

// renderClientUnreceivedPackets returns, given a list of sequences, the
// sequences for which no counterparty packet commitments have been received.
// This is done by checking if a receipt exists on this chain for the packet
// sequence.
func renderClientUnreceivedPackets(w *mux.ResponseWriter, r *mux.Request) {
	id := r.GetVar("id")
	c := store.getClient(id)
	if c == nil {
		renderNode(w, nodeErrorClientNotFound(id))
		return
	}
	seqs := strings.Split(strings.TrimSpace(r.Query.Get("sequences")), ",")
	var unreceivedSeqs []*json.Node
	for _, seq := range seqs {
		seqi, err := strconv.ParseUint(seq, 10, 64)
		if err != nil {
			renderNode(w, nodeError(ufmt.Sprintf("invalid sequence %q: %v", seq, err)))
			return
		}
		if !c.hasPacketReceipt(seqi) {
			unreceivedSeqs = append(unreceivedSeqs, json.StringNode("", seq))
		}
	}
	renderNode(w, json.ObjectNode("", map[string]*json.Node{
		"height":               renderHeight(types.GetSelfHeight()),
		"unreceived_sequences": json.ArrayNode("", unreceivedSeqs),
	}))
}

// Implements jsonpage.JSONRenderer
func (c *client) RenderJSON() *json.Node {
	m := map[string]*json.Node{
		"id":                     json.StringNode("", c.id),
		"type":                   json.StringNode("", c.typ),
		"creator":                json.StringNode("", c.creator.String()),
		"status":                 json.StringNode("", c.lightClient.Status()),
		"counterparty_client_id": json.StringNode("", c.counterpartyClientID),
	}
	var prefixes []*json.Node
	for _, m := range c.counterpartyMerklePrefix {
		prefixes = append(prefixes, json.StringNode("", string(m)))
	}
	m["counterparty_merke_prefix"] = json.ArrayNode("", prefixes)
	switch c.typ {
	case lightclient.Tendermint:
		lc := c.lightClient.(*tendermint.TMLightClient)
		m["client_state"] = json.ObjectNode("", map[string]*json.Node{
			"chain_id":         json.StringNode("", lc.ClientState.ChainID),
			"latest_height":    renderHeight(lc.ClientState.LatestHeight),
			"frozen_height":    renderHeight(lc.ClientState.FrozenHeight),
			"trust_level":      renderFraction(lc.ClientState.TrustLevel),
			"trusting_period":  renderDuration(lc.ClientState.TrustingPeriod),
			"unbonding_period": renderDuration(lc.ClientState.UnbondingPeriod),
			"max_clock_drift":  renderDuration(lc.ClientState.MaxClockDrift),
			"upgrade_path":     renderStrings(lc.ClientState.UpgradePath),
		})
		lastConsState, found := lc.GetConsensusState(lc.LatestHeight())
		if found {
			m["last_consensus_state"] = renderConsensusState(lc.LatestHeight(), lastConsState)
		}
	}
	return json.ObjectNode("", m)
}

func (c *client) renderConsensusStates(r *mux.Request) *json.Node {
	switch c.typ {
	case lightclient.Tendermint:
		lc := c.lightClient.(*tendermint.TMLightClient)
		return jsonpage.Render(lc.ConsensusStateByHeight, r, func(k string, v any) *json.Node {
			cs := v.(*tendermint.ConsensusState)
			height := types.ParseHeightNatSort(k)
			return renderConsensusState(height, cs)
		})
	}
	return nodeError("unhandled client type %s", c.typ)
}

func renderConsensusState(height types.Height, cs *tendermint.ConsensusState) *json.Node {
	return json.ObjectNode("", map[string]*json.Node{
		"height":               renderHeight(height),
		"timestamp":            json.NumberNode("", float64(cs.Timestamp.Unix())),
		"root":                 json.StringNode("", base64.StdEncoding.EncodeToString(cs.Root.Hash)),
		"next_validators_hash": json.StringNode("", base64.StdEncoding.EncodeToString(cs.NextValidatorsHash)),
	})
}

func renderPkgPath(path string) string {
	const prefix = "gno.land"
	if strings.HasPrefix(path, prefix) {
		return ufmt.Sprintf("[`%s`](%s)", path, path[len(prefix):])
	}
	return "`" + path + "`"
}

func renderAddr(addr address) string {
	s := addr.String()
	short := s
	if len(s) > 10 {
		short = s[:6] + "…" + s[len(s)-4:]
	}
	return ufmt.Sprintf("[%s](/u/%s)", short, s)
}

func renderHeight(h types.Height) *json.Node {
	return json.ObjectNode("", map[string]*json.Node{
		"revision_number": json.NumberNode("", float64(h.RevisionNumber)),
		"revision_height": json.NumberNode("", float64(h.RevisionHeight)),
	})
}

func renderFraction(f tendermint.Fraction) *json.Node {
	return json.ObjectNode("", map[string]*json.Node{
		"numerator":   json.NumberNode("", float64(f.Numerator)),
		"denominator": json.NumberNode("", float64(f.Denominator)),
	})
}

func renderDuration(d time.Duration) *json.Node {
	return json.NumberNode("", d.Seconds())
}

func renderStrings(s []string) *json.Node {
	var nodes []*json.Node
	for _, s := range s {
		nodes = append(nodes, json.StringNode("", s))
	}
	return json.ArrayNode("", nodes)
}

func renderNode(w *mux.ResponseWriter, n *json.Node) {
	bz, err := json.Marshal(n)
	if err != nil {
		panic(err)
	}
	w.Write(string(bz))
}

func nodeErrorClientNotFound(id string) *json.Node {
	return nodeError("client %s not found", id)
}

func nodeError(msg string, args ...any) *json.Node {
	return json.ObjectNode("", map[string]*json.Node{
		"error": json.StringNode("", ufmt.Sprintf(msg, args...)),
	})
}

func renderAdmin(w *mux.ResponseWriter, r *mux.Request) {
	var out strings.Builder
	out.WriteString("## Admin & Relayers\n\n")
	out.WriteString(ufmt.Sprintf("- **Admin**: %s\n", renderAddr(admin)))
	if relayers.Size() == 0 {
		out.WriteString("- **Relayers**: any (whitelist empty)\n")
	} else {
		out.WriteString("- **Relayers**:\n")
		relayers.Iterate("", "", func(k string, v any) bool {
			out.WriteString(ufmt.Sprintf("  - %s\n", renderAddr(address(k))))
			return false
		})
	}
	w.Write(out.String())
}

package core

import (
	"chain/params"

	"gno.land/p/aib/ibc/app"
	"gno.land/p/aib/ibc/host"
	"gno.land/p/aib/ibc/lightclient"
	"gno.land/p/aib/ibc/lightclient/tendermint"
	"gno.land/p/aib/ibc/types"
	"gno.land/p/nt/bptree/v0"
	"gno.land/p/nt/seqid/v0"
	"gno.land/p/nt/ufmt/v0"
)

var store *Store

func init() {
	store = newStore()
}

type Store struct {
	clientSeq  seqid.ID
	clientByID *bptree.BPTree // id:client

	routes map[string]ibcApp
}

func newStore() *Store {
	return &Store{
		clientByID: bptree.NewBPTree32(),
		routes:     make(map[string]ibcApp),
	}
}

type client struct {
	id                       string
	typ                      string
	creator                  address
	counterpartyClientID     string
	counterpartyMerklePrefix [][]byte

	lightClient lightclient.Interface

	sendSeq                     seqid.ID
	packetCommitmentsBySeq      *bptree.BPTree // sequence:commitment
	packetReceiptsBySeq         *bptree.BPTree // sequence:receipt
	packetAcknowledgementsBySeq *bptree.BPTree // sequence:ack
	pendingAsyncAcksBySeq       *bptree.BPTree // sequence:pendingAsyncAck
}

type ibcApp struct {
	app.IBCApp
	pkgPath string
	address address
}

type pendingAsyncAck struct {
	packet     types.Packet
	appPkgPath string
}

func (c *client) getPacketCommitment(sequence uint64) []byte {
	v := c.packetCommitmentsBySeq.Get(seqid.ID(sequence).Binary())
	if v == nil {
		return nil
	}
	return v.([]byte)
}

// setPacketCommitment stores the packet commitment in the client data and in
// the params.
func (c *client) setPacketCommitment(sequence uint64, packet types.Packet) {
	commitment := types.CommitPacket(packet)

	// store in client data
	c.packetCommitmentsBySeq.Set(seqid.ID(sequence).Binary(), commitment)

	// store in params, so it is provable by the counterparty
	// The key will be: (abci path=.store/main/key)
	// "/pv/vm:gno.land/r/aib/ibc/core:" + clientID + "1" + sequence
	key := host.PacketCommitmentKey(c.id, sequence)
	setChainParam(key, commitment)
}

func (c *client) deletePacketCommitment(sequence uint64) {
	c.packetCommitmentsBySeq.Remove(seqid.ID(sequence).Binary())

	key := host.PacketCommitmentKey(c.id, sequence)
	setChainParam(key, nil)
}

// hasPacketReceipt returns true if the packet receipt exists, otherwise false.
func (c *client) hasPacketReceipt(sequence uint64) bool {
	return c.packetReceiptsBySeq.Has(seqid.ID(sequence).Binary())
}

// setPacketReceipt writes the packet receipt under the receipt path
// This is a public path that is standardized by the IBC V2 specification.
func (c *client) setPacketReceipt(sequence uint64) {
	value := []byte{byte(2)} // constant value

	// store in client data
	c.packetReceiptsBySeq.Set(seqid.ID(sequence).Binary(), value)

	// store in params, so it is provable by the counterparty
	// The key will be: (abci path=.store/main/key)
	// "/pv/vm:gno.land/r/aib/ibc/core:" + clientID + "2" + sequence
	key := host.PacketReceiptKey(c.id, sequence)
	setChainParam(key, value)
}

func (c *client) deletePacketReceipt(sequence uint64) {
	c.packetReceiptsBySeq.Remove(seqid.ID(sequence).Binary())

	key := host.PacketReceiptKey(c.id, sequence)
	setChainParam(key, nil)
}

// hasPacketAcknowledgement checks if the packet ack hash is already on the
// store.
func (c *client) hasPacketAcknowledgement(sequence uint64) bool {
	return c.packetAcknowledgementsBySeq.Has(seqid.ID(sequence).Binary())
}

// GetPacketAcknowledgement fetches the packet acknowledgement from the store.
func (c *client) getPacketAcknowledgement(sequence uint64) []byte {
	v := c.packetAcknowledgementsBySeq.Get(seqid.ID(sequence).Binary())
	if v == nil {
		return nil
	}
	return v.([]byte)
}

func (c *client) savePendingAsyncAck(packet types.Packet, appPkgPath string) {
	sequence := packet.Sequence
	if c.hasPendingAsyncAck(sequence) {
		panic(ufmt.Sprintf("pending async ack already exists for sequence %d", sequence))
	}
	if c.hasPacketAcknowledgement(sequence) {
		panic(ufmt.Sprintf("acknowledgement already written for sequence %d", sequence))
	}
	c.pendingAsyncAcksBySeq.Set(seqid.ID(sequence).Binary(), &pendingAsyncAck{
		packet:     packet,
		appPkgPath: appPkgPath,
	})
}

func (c *client) getPendingAsyncAck(sequence uint64) (*pendingAsyncAck, bool) {
	v := c.pendingAsyncAcksBySeq.Get(seqid.ID(sequence).Binary())
	if v == nil {
		return nil, false
	}
	return v.(*pendingAsyncAck), true
}

func (c *client) deletePendingAsyncAck(sequence uint64) {
	c.pendingAsyncAcksBySeq.Remove(seqid.ID(sequence).Binary())
}

func (c *client) hasPendingAsyncAck(sequence uint64) bool {
	return c.pendingAsyncAcksBySeq.Has(seqid.ID(sequence).Binary())
}

// SetPacketAcknowledgement writes the acknowledgement hash under the
// acknowledgement path
// This is a public path that is standardized by the IBC V2 specification.
func (c *client) setPacketAcknowledgement(sequence uint64, ackHash []byte) {
	// store in client data
	c.packetAcknowledgementsBySeq.Set(seqid.ID(sequence).Binary(), ackHash)

	// store in params, so it is provable by the counterparty
	// The key will be: (abci path=.store/main/key)
	// "/pv/vm:gno.land/r/aib/ibc/core:" + clientID + "3" + sequence
	key := host.PacketAcknowledgementKey(c.id, sequence)
	setChainParam(key, ackHash)
}

func (c *client) deletePacketAcknowledgement(sequence uint64) {
	c.packetAcknowledgementsBySeq.Remove(seqid.ID(sequence).Binary())

	key := host.PacketAcknowledgementKey(c.id, sequence)
	setChainParam(key, nil)
}

func setChainParam(key, value []byte) {
	// TODO find a way to assert this write in tests (difficult since params does
	// not expose getters)
	params.SetBytes(string(key), value)
}

func (cs *Store) addClient(typ string, creator address) *client {
	id := ufmt.Sprintf("%s-%d", typ, uint64(cs.clientSeq.Next()))
	c := &client{
		id:      id,
		typ:     typ,
		creator: creator,

		packetCommitmentsBySeq:      bptree.NewBPTree32(),
		packetReceiptsBySeq:         bptree.NewBPTree32(),
		packetAcknowledgementsBySeq: bptree.NewBPTree32(),
		pendingAsyncAcksBySeq:       bptree.NewBPTree32(),
	}
	switch typ {
	case lightclient.Tendermint:
		c.lightClient = tendermint.NewTMLightClient()
	default:
		panic("unhandled light client type " + typ)
	}
	cs.clientByID.Set(id, c)
	return c
}

func (cs *Store) getClient(id string) *client {
	cli := cs.clientByID.Get(id)
	if cli == nil {
		return nil
	}
	return cli.(*client)
}

// route returns an IBCApp for the given portID.
func (cs *Store) route(portID string) ibcApp {
	app, ok := cs.routes[portID]
	if !ok {
		panic(ufmt.Sprintf("no registered app for port %s", portID))
	}
	return app
}

