	"gno.land/r/aib/ibc/core"
)

// transferRealmPath is the package path of this realm; used to compute
// per-voucher GRC20 registry keys. Hardcoded because we cannot read it from
// runtime.CurrentRealm() in v2 without the unsafe package, and Render needs
// it from a non-crossing render handler.
const transferRealmPath = "gno.land/r/aib/ibc/apps/transfer"

func Render(path string) string {
	router := mux.NewRouter()
	router.HandleFunc("", renderHome)
	router.HandleFunc("denoms", renderDenoms)
	router.HandleFunc("denoms/ibc/{hash}", renderDenom)
	router.HandleFunc("total_escrow/{denom}", renderTotalEscrowForDenom)
	router.HandleFunc("vouchers", renderVouchers)
	router.HandleFunc("voucher/ibc/{hash}", renderVoucher)
	router.HandleFunc("voucher/ibc/{hash}/balance/{addr}", renderVoucherBalance)
	return router.Render(path)
}

func renderHome(w *mux.ResponseWriter, r *mux.Request) {
	var out strings.Builder
	out.WriteString("# IBC transfer\n\n")
	out.WriteString("ICS-20 style transfer state and voucher token queries.\n\n")
	out.WriteString(renderTransferLinks())
	out.WriteString(ufmt.Sprintf("## Vouchers (%d)\n\n", denoms.Size()))
	if denoms.Size() > 0 {
		out.WriteString("| Denom | Base | Path | Supply | GRC20 | Actions |\n")
		out.WriteString("|-------|------|------|--------|-------|---------|\n")
		for _, d := range denomsByClientOrder() {
			ibcDenom := d.IBCDenom()
			supply := ""
			grc20link := ""
			if inst := getVoucher(ibcDenom); inst != nil {
				supply = ufmt.Sprintf("[%d](/r/aib/ibc/apps/transfer:voucher/%s)", inst.token.TotalSupply(), ibcDenom)
				key := grc20regKey(ibcDenom)
				// Shorten the hash suffix: "gno.land/r/.../transfer.CAEF9C..." → keep prefix + first 4 … last 4 of hash
				dotIdx := strings.LastIndex(key, ".")
				shortKey := key
				if dotIdx != -1 {
					hash := key[dotIdx+1:]
					if len(hash) > 10 {
						shortKey = key[:dotIdx+1] + hash[:4] + "…" + hash[len(hash)-4:]
					}
				}
				const grc20regPath = "gno.land/r/demo/defi/grc20reg"
				grc20link = ufmt.Sprintf("[%s](%s:%s)", shortKey, stripDomain(grc20regPath), key)
			}
			// Actions: IBC "send back" (via the voucher's source client) plus
			// local GRC20 send/approve. All pre-fill the voucher denom; the user
			// only fills the counterparty and amount (and timeout for the IBC
			// send) in their wallet.
			sourceClient := d.Trace[0].ClientId
			actions := ufmt.Sprintf(
				"[send back](%s) via `%s` — [send](%s) — [approve](%s)",
				newTransferLink(sourceClient, "", ibcDenom).URL(),
				sourceClient,
				newVoucherSendLink(ibcDenom).URL(),
				newVoucherApproveLink(ibcDenom).URL(),
			)
			out.WriteString(ufmt.Sprintf(
				"| [`%s`](/r/aib/ibc/apps/transfer:denoms/%s) | %s | %s | %s | %s | %s |\n",
				shortDenom(ibcDenom), ibcDenom, d.Base, d.Path(), supply, grc20link, actions,
			))
		}
		out.WriteString("\n")
	} else {
		out.WriteString("No vouchers yet.\n\n")
	}
	out.WriteString(ufmt.Sprintf("## Escrow (%d)\n\n", totalEscrow.Size()))
	if totalEscrow.Size() > 0 {
		out.WriteString("| Denom | Amount |\n")
		out.WriteString("|-------|--------|\n")
		totalEscrow.IterateByOffset(0, totalEscrow.Size(), func(_ string, v any) bool {
			c := v.(chain.Coin)
			out.WriteString(ufmt.Sprintf(
				"| [`%s`](/r/aib/ibc/apps/transfer:total_escrow/%s) | %d |\n",
				c.Denom, c.Denom, c.Amount,
			))
			return false
		})
		out.WriteString("\n")
	} else {
		out.WriteString("No escrow yet.\n\n")
	}
	out.WriteString("## JSON endpoints\n\n")
	out.WriteString("- [`denoms`](/r/aib/ibc/apps/transfer:denoms): list known IBC denoms (`?page`, `?limit`)\n")
	out.WriteString("- `denoms/ibc/{hash}`: get metadata for an IBC denom\n")
	out.WriteString("- `total_escrow/{denom}`: get total escrow tracked for a base denom\n")
	out.WriteString("- [`vouchers`](/r/aib/ibc/apps/transfer:vouchers): list voucher tokens (`?page`, `?limit`)\n")
	out.WriteString("- `voucher/ibc/{hash}`: get voucher token metadata\n")
	out.WriteString("- `voucher/ibc/{hash}/balance/{addr}`: get a voucher balance for an address\n\n")
	w.Write(out.String())
}

func renderDenoms(w *mux.ResponseWriter, r *mux.Request) {
	renderNode(w, jsonpage.Render(denoms, r, nil))
}

func renderDenom(w *mux.ResponseWriter, r *mux.Request) {
	denom := "ibc/" + r.GetVar("hash")
	d := denoms.Get(denom)
	if d == nil {
		renderNode(w, nodeError(ufmt.Sprintf("denom %s not found", denom)))
		return
	}
	renderNode(w, d.(Denom).RenderJSON())
}

func renderTotalEscrowForDenom(w *mux.ResponseWriter, r *mux.Request) {
	denom := r.GetVar("denom")
	var amt int64
	x := totalEscrow.Get(denom)
	if x != nil {
		amt = x.(chain.Coin).Amount
	}
	renderNode(w, json.ObjectNode("", map[string]*json.Node{
		"denom":  json.StringNode("", denom),
		"amount": json.NumberNode("", float64(amt)),
	}))
}

func renderVouchers(w *mux.ResponseWriter, r *mux.Request) {
	renderNode(w, jsonpage.Render(voucherTokens, r, func(key string, v any) *json.Node {
		inst := v.(*voucher)
		return json.ObjectNode("", map[string]*json.Node{
			"denom":        json.StringNode("", key),
			"grc20reg_key": json.StringNode("", grc20regKey(key)),
			"name":         json.StringNode("", inst.token.GetName()),
			"symbol":       json.StringNode("", inst.token.GetSymbol()),
			"decimals":     json.NumberNode("", float64(inst.token.GetDecimals())),
			"total_supply": json.NumberNode("", float64(inst.token.TotalSupply())),
		})
	}))
}

func renderVoucher(w *mux.ResponseWriter, r *mux.Request) {
	ibcDenom := "ibc/" + r.GetVar("hash")
	inst := getVoucher(ibcDenom)
	if inst == nil {
		renderNode(w, nodeError("voucher token %s not found", ibcDenom))
		return
	}
	renderNode(w, json.ObjectNode("", map[string]*json.Node{
		"denom":        json.StringNode("", ibcDenom),
		"grc20reg_key": json.StringNode("", grc20regKey(ibcDenom)),
		"name":         json.StringNode("", inst.token.GetName()),
		"symbol":       json.StringNode("", inst.token.GetSymbol()),
		"decimals":     json.NumberNode("", float64(inst.token.GetDecimals())),
		"total_supply": json.NumberNode("", float64(inst.token.TotalSupply())),
	}))
}

func renderVoucherBalance(w *mux.ResponseWriter, r *mux.Request) {
	ibcDenom := "ibc/" + r.GetVar("hash")
	addr := r.GetVar("addr")
	inst := getVoucher(ibcDenom)
	if inst == nil {
		renderNode(w, nodeError("voucher token %s not found", ibcDenom))
		return
	}
	balance := inst.token.BalanceOf(address(addr))
	renderNode(w, json.ObjectNode("", map[string]*json.Node{
		"denom":   json.StringNode("", ibcDenom),
		"address": json.StringNode("", addr),
		"balance": json.NumberNode("", float64(balance)),
	}))
}

// denomsByClientOrder returns the stored voucher denoms ordered to match the
// "Pick the client" listing (core.ClientIDs() order): each voucher is grouped
// under its source client (Trace[0].ClientId), following the same client order
// as the client list, so the vouchers table lines up with it. Within a client,
// the underlying b+tree order is preserved. Denoms whose source client is not
// (or no longer) registered are appended last, in b+tree order, so nothing is
// dropped. Every stored denom is a minted voucher with a non-empty trace, so
// Trace[0] is always safe to read.
func denomsByClientOrder() []Denom {
	byClient := make(map[string][]Denom)
	all := make([]Denom, 0, denoms.Size())
	denoms.IterateByOffset(0, denoms.Size(), func(_ string, v any) bool {
		d := v.(Denom)
		all = append(all, d)
		client := d.Trace[0].ClientId
		byClient[client] = append(byClient[client], d)
		return false
	})

	out := make([]Denom, 0, len(all))
	emitted := make(map[string]bool) // source clients already emitted
	for _, client := range core.ClientIDs() {
		if ds, ok := byClient[client]; ok {
			out = append(out, ds...)
			emitted[client] = true
		}
	}
	for _, d := range all {
		if !emitted[d.Trace[0].ClientId] {
			out = append(out, d)
		}
	}
	return out
}

// renderTransferLinks returns the "## Transfer" section: a set of txlinks
// that wallets can turn into MsgCalls to Transfer. Each link leaves at least
// one argument empty so the user fills it in their wallet.
func renderTransferLinks() string {
	var out strings.Builder
	out.WriteString("## Transfer\n\n")

	clientIDs := core.ClientIDs()
	if len(clientIDs) == 0 {
		out.WriteString("No IBC client registered yet — create one in [`/r/aib/ibc/core`](/r/aib/ibc/core) before transferring.\n\n")
		return out.String()
	}

	out.WriteString("Trigger an IBC transfer from your wallet. Pick the client of the destination chain:\n\n")
	for _, clientID := range clientIDs {
		status := core.ClientStatus(clientID)
		height := core.ClientLatestHeight(clientID)
		if status == lightclient.Active {
			out.WriteString(ufmt.Sprintf(
				"- [send via `%s`](%s) — %s, trusted height `%s` ([client details](/r/aib/ibc/core:clients/%s))\n",
				clientID, newTransferLink(clientID, "", "").URL(), status, height, clientID,
			))
		} else {
			// Non-active client: no send link, since packets can't be sent.
			out.WriteString(ufmt.Sprintf(
				"- `%s` — %s, trusted height `%s` ([client details](/r/aib/ibc/core:clients/%s))\n",
				clientID, status, height, clientID,
			))
		}
	}

	out.WriteString("\n")
	return out.String()
}

// newVoucherSendLink builds a txlink to VoucherSend with the ibc denom
// pre-filled. The user fills `to` and `amount` in their wallet.
func newVoucherSendLink(ibcDenom string) *txlink.TxBuilder {
	return txlink.NewLink("VoucherSend").AddArgs(
		"ibcDenom", ibcDenom,
		"to", "",
		"amount", "",
	)
}

// newVoucherApproveLink builds a txlink to VoucherApprove with the ibc denom
// pre-filled. The user fills `spender` and `amount` in their wallet.
func newVoucherApproveLink(ibcDenom string) *txlink.TxBuilder {
	return txlink.NewLink("VoucherApprove").AddArgs(
		"ibcDenom", ibcDenom,
		"spender", "",
		"amount", "",
	)
}

// newTransferLink builds a txlink to the Transfer function with the given
// pre-filled arguments. Empty values are left wallet-settable.
// timeoutTimestamp defaults to one hour from now (in unix seconds), matching
// what the e2e tests use; the user can still override it in their wallet.
func newTransferLink(clientID, receiver, denom string) *txlink.TxBuilder {
	timeoutTimestamp := strconv.FormatInt(time.Now().Add(time.Hour).Unix(), 10)
	return txlink.NewLink("Transfer").AddArgs(
		"clientID", clientID,
		"receiver", receiver,
		"denom", denom,
		"amount", "",
		"timeoutTimestamp", timeoutTimestamp,
		"memo", "",
	)
}

// stripDomain removes the domain from a gno pkg path for use in URLs.
// "gno.land/r/demo/foo" → "/r/demo/foo"
func stripDomain(path string) string {
	i := strings.Index(path, "/")
	if i != -1 {
		return path[i:]
	}
	return path
}

// shortDenom shortens an IBC denom hash for display.
// "ibc/CAEF9CABC…9D0F" (ibc/ + first 4 + … + last 4)
func shortDenom(ibcDenom string) string {
	const prefix = "ibc/"
	if !strings.HasPrefix(ibcDenom, prefix) {
		return ibcDenom
	}
	hash := ibcDenom[len(prefix):]
	if len(hash) > 10 {
		return prefix + hash[:4] + "…" + hash[len(hash)-4:]
	}
	return ibcDenom
}

func renderNode(w *mux.ResponseWriter, n *json.Node) {
	bz, err := json.Marshal(n)
	if err != nil {
		panic(err)
	}
	w.Write(string(bz))
}

// grc20regKey returns the grc20reg key for a voucher ibc denom.
// e.g. "ibc/CAEF9C..." → "gno.land/r/aib/ibc/apps/transfer.CAEF9C..."
func grc20regKey(ibcDenom string) string {
	return transferRealmPath + "." + ibcDenom[len("ibc/"):]
}

func nodeError(msg string, args ...any) *json.Node {
	return json.ObjectNode("", map[string]*json.Node{
		"error": json.StringNode("", ufmt.Sprintf(msg, args...)),
	})
}

package transfer

import (
	"chain"
	"strings"

	"gno.land/p/demo/tokens/grc20"
	"gno.land/p/nt/bptree/v0"
	"gno.land/p/nt/seqid/v0"
	"gno.land/r/demo/defi/grc20reg"
)

var (
	denoms        *bptree.BPTree // ibcDenom:Denom
	totalEscrow   *bptree.BPTree // denom:chain.Coin
	voucherTokens *bptree.BPTree // ibcDenom:*voucher

	// nextVoucherID allocates a unique grc20 token id for each voucher. Voucher
	// symbols are truncated IBC-hash prefixes that can collide, so a shared
	// monotonic id keeps every token's grc20 identifier distinct.
	nextVoucherID seqid.ID
)

// voucher holds a voucher token and its private ledger for mint/burn.
type voucher struct {
	token  *grc20.Token
	ledger *grc20.PrivateLedger
}

func init() {
	denoms = bptree.NewBPTree32()
	totalEscrow = bptree.NewBPTree32()
	voucherTokens = bptree.NewBPTree32()
}

func hasDenom(voucherDenom string) bool {
	return denoms.Has(voucherDenom)
}

func setDenom(denom Denom) {
	denoms.Set(denom.IBCDenom(), denom)
}

func getDenom(ibcDenom string) (Denom, bool) {
	d := denoms.Get(ibcDenom)
	if d == nil {
		return Denom{}, false
	}
	return d.(Denom), true
}

func addEscrowForDenom(c chain.Coin) {
	d := totalEscrow.Get(c.Denom)
	if d != nil {
		c = d.(chain.Coin).Add(c)
	}
	totalEscrow.Set(c.Denom, c)
}

func subEscrowForDenom(c chain.Coin) {
	x := totalEscrow.Get(c.Denom)
	if x == nil {
		x = chain.Coin{Denom: c.Denom}
	}
	c = x.(chain.Coin).Sub(c)
	totalEscrow.Set(c.Denom, c)
}

// VoucherSymbol returns the grc20 token symbol for an IBC voucher denom: the IBC
// hash truncated to grc20's MaxSymbolLen. The full voucherDenom ("ibc/<64-hex-
// hash>") can't be a symbol because v2 grc20 enforces MaxSymbolLen and
// [A-Za-z0-9_-] only. Since grc20reg keys tokens by rlmpath.symbol, this is also
// the symbol component of a voucher's registry key, so callers locate a voucher
// via grc20reg.Get(<this realm's pkgpath> + "." + VoucherSymbol(ibcDenom)).
func VoucherSymbol(ibcDenom string) string {
	symbol := strings.TrimPrefix(ibcDenom, "ibc/")
	if len(symbol) > grc20.MaxSymbolLen {
		symbol = symbol[:grc20.MaxSymbolLen]
	}
	return symbol
}

// getOrCreateVoucher returns the existing voucher instance for the given IBC
// denom, or creates a new one and registers it in grc20reg for DeFi
// discoverability. Non-crossing helper; rlm is needed to issue the cross
// call into grc20reg.Register from this realm's frame.
//
// The token symbol is a truncated IBC hash (see VoucherSymbol); its name is the
// base denom, and nextVoucherID keeps each token's grc20 id distinct. grc20reg
// keys the token by rlmpath.symbol (not the slug), so the full-hash slug is
// retained only as event metadata. Because the key is the truncated symbol,
// two vouchers whose hashes share an 11-char prefix would collide on the
// registry key (astronomically unlikely, but no longer guarded by the slug).
func getOrCreateVoucher(_ int, rlm realm, baseDenom, voucherDenom string) *voucher {
	if v := voucherTokens.Get(voucherDenom); v != nil {
		return v.(*voucher)
	}
	token, ledger := grc20.NewToken(baseDenom, VoucherSymbol(voucherDenom), 0, nextVoucherID.Next(), rlm)
	inst := &voucher{token: token, ledger: ledger}
	voucherTokens.Set(voucherDenom, inst)
	grc20reg.Register(cross(rlm), token, voucherDenom[len("ibc/"):])
	return inst
}

// getVoucher returns the voucher instance for the given IBC denom, or nil if not
// found.
func getVoucher(ibcDenom string) *voucher {
	v := voucherTokens.Get(ibcDenom)
	if v == nil {
		return nil
	}
	return v.(*voucher)
}

// VoucherBalanceOf returns the balance of a voucher token for a given address.
// Returns 0 if the token does not exist.
func VoucherBalanceOf(ibcDenom string, addr address) int64 {
	inst := getVoucher(ibcDenom)
	if inst == nil {
		return 0
	}
	return inst.token.BalanceOf(addr)
}

// GRC20Alias returns a slash-free alias for a GRC20 denom (grc20reg key)
// by replacing "/" with ":". This is safe because grc20reg slugs are
// alphanumeric (enforced by grc20reg.Register), so colons never appear in
// grc20reg keys, making the replacement reversible.
// Examples:
//
//	"gno.land/r/demo/foo"      → "gno.land:r:demo:foo"
//	"gno.land/r/demo/foo.FOO"  → "gno.land:r:demo:foo.FOO"
func GRC20Alias(grc20regKey string) string {
	return strings.ReplaceAll(grc20regKey, "/", ":")
}

// resolveGRC20Alias converts a GRC20 alias back to the grc20reg key
// by replacing ":" with "/".
func resolveGRC20Alias(alias string) string {
	return strings.ReplaceAll(alias, ":", "/")
}

// isGRC20Alias returns true if the denom is a GRC20 alias.
// GRC20 aliases always start with "gno.land:" (the colon form of "gno.land/").
func isGRC20Alias(denom string) bool {
	return strings.HasPrefix(denom, "gno.land:")
}

package transfer

import (
	"testing"

	"gno.land/p/nt/uassert/v0"
)

func TestGRC20AliasRoundTrip(t *testing.T) {
	testCases := []struct {
		name     string
		key      string
		expAlias string
	}{
		{
			"simple path without slug",
			"gno.land/r/demo/foo",
			"gno.land:r:demo:foo",
		},
		{
			"path with slug",
			"gno.land/r/demo/foo.FOO",
			"gno.land:r:demo:foo.FOO",
		},
		{
			"path with alphanumeric slug",
			"gno.land/r/demo/foo.Bar123",
			"gno.land:r:demo:foo.Bar123",
		},
	}
	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			alias := GRC20Alias(tc.key)
			uassert.Equal(t, tc.expAlias, alias)

			got := resolveGRC20Alias(alias)
			uassert.Equal(t, tc.key, got)
		})
	}
}

func TestIsGRC20Alias(t *testing.T) {
	testCases := []struct {
		name   string
		denom  string
		expect bool
	}{
		{"grc20 alias", "gno.land:r:demo:foo.FOO", true},
		{"native denom", "ugnot", false},
		{"ibc denom", "ibc/ABC123", false},
		{"gno path not aliased", "gno.land/r/demo/foo", false},
	}
	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			uassert.Equal(t, tc.expect, isGRC20Alias(tc.denom))
		})
	}
}

package transfer

import (
	"chain"
	"strconv"

	"gno.land/p/nt/ufmt/v0"
)

// Token defines a struct which represents a token to be transferred.
type Token struct {
	// the token denomination
	Denom Denom
	// the token amount to be transferred
	Amount string
}

// NewToken constructs a Token with the given native base denom and amount
// (no trace, no prefix hops). Provided so external callers — which cannot
// construct foreign-stamped composite literals under v2 borrow rule #1 —
// can still build Token values for tests and packet assembly.
func NewToken(baseDenom, amount string) Token {
	return Token{
		Denom:  NewDenom(baseDenom),
		Amount: amount,
	}
}

// ToCoin converts a Token to an chain.Coin.
//
// The function parses the Token.Amount field and returns a new sdk.Coin with
// the IBCDenom of the Token's Denom field and the parsed Amount.
// If the Amount cannot be parsed, an error is returned with a wrapped error
// message.
func (t Token) ToCoin() (chain.Coin, error) {
	amt, err := t.AmountInt64()
	if err != nil {
		return chain.Coin{}, err
	}
	return chain.NewCoin(t.Denom.IBCDenom(), amt), nil
}

func (t Token) AmountInt64() (int64, error) {
	amt, err := strconv.ParseInt(t.Amount, 10, 64)
	if err != nil {
		return 0, ufmt.Errorf("unable to parse amount %q into int64", t.Amount)
	}
	return amt, nil
}

package transfer_test

import (
	"chain"
	"testing"

	"gno.land/p/nt/uassert/v0"
	"gno.land/p/nt/urequire/v0"
	"gno.land/r/aib/ibc/apps/transfer"
)

func TestTokenToCoin(t *testing.T) {
	const (
		tokenDenom  = "atom/pool"
		tokenAmount = "100"
	)
	testCases := []struct {
		name     string
		token    transfer.Token
		expCoin  chain.Coin
		expError string
	}{
		{
			"success: convert token to coin",
			transfer.NewToken(tokenDenom, tokenAmount),
			chain.NewCoin(tokenDenom, 100),
			"",
		},
		{
			"failure: invalid amount string",
			transfer.NewToken(tokenDenom, "value"),
			chain.Coin{},
			"unable to parse amount \"value\" into int64",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {

			coin, err := tc.token.ToCoin()

			if tc.expError == "" {
				urequire.NoError(t, err, tc.name)
				return
			}
			urequire.ErrorContains(t, err, tc.expError)
			uassert.Equal(t, tc.expCoin.Amount, coin.Amount)
			uassert.Equal(t, tc.expCoin.Denom, coin.Denom)
		})
	}
}

package transfer

import (
	"chain"
	"chain/banker"
	"chain/runtime/unsafe"
	"strings"

	"gno.land/p/aib/ibc/types"
	"gno.land/p/nt/ufmt/v0"
	"gno.land/r/aib/ibc/core"
	"gno.land/r/demo/defi/grc20reg"
)

// Transfer is the entry point for sending tokens to another chain using the
// IBC protocol. It supports three token types, detected automatically from the
// denom argument:
//   - IBC voucher (denom starts with "ibc/"): burns the voucher GRC20 token.
//   - Non-IBC GRC20 token (registered in grc20reg): escrows via TransferFrom.
//   - Native coin (everything else): the coin must be sent with the transaction
//     via the send field, and must match denom and amount.
//
// memo is included in the IBC packet payload.
func Transfer(cur realm, clientID, receiver, denom string, amount int64, timeoutTimestamp uint64, memo string) (
	packet types.MsgSendPacket, sequence uint64,
) {
	switch {
	case strings.HasPrefix(denom, "ibc/"):
		// IBC voucher: value-moving authority must come from a direct
		// user call because the packet sender is the tx origin.
		if !cur.Previous().IsUserCall() {
			panic("voucher transfer must be a direct user call (maketx call)")
		}
		// The voucher GRC20 token is burnt in OnSendPacket. Native coins sent
		// with a voucher transfer would be stuck at this realm.
		if len(unsafe.OriginSend()) > 0 {
			panic("voucher transfer must not include native coins")
		}
		// Validate it exists and resolve the denom path.
		if getVoucher(denom) == nil {
			panic(ufmt.Errorf("voucher token not found for denom %s", denom))
		}
		d, found := getDenom(denom)
		if !found {
			panic(ufmt.Sprintf("denom %s not found in store", denom))
		}
		pendingVoucherSend = &pendingSend{
			sender:       unsafe.OriginCaller().String(),
			sourceClient: clientID,
			denom:        d.Path(),
			amount:       amount,
		}
		defer func() { pendingVoucherSend = nil }()
		denom = d.Path()
	case grc20reg.Get(denom) != nil:
		// Non-IBC GRC20 token: value-moving authority must come from a
		// direct user call before OnSendPacket spends prior approval.
		if !cur.Previous().IsUserCall() {
			panic("GRC20 transfer must be a direct user call (maketx call)")
		}
		// Escrow via TransferFrom happens in OnSendPacket. Native coins sent
		// with a GRC20 transfer would be stuck at this realm.
		if len(unsafe.OriginSend()) > 0 {
			panic("GRC20 transfer must not include native coins")
		}
		// Replace the denom with a slash-free alias for the IBC packet.
		// This avoids ibc-go rejecting base denoms containing slashes.
		alias := GRC20Alias(denom)
		pendingGRC20Send = &pendingSend{
			sender:       unsafe.OriginCaller().String(),
			sourceClient: clientID,
			denom:        alias,
			amount:       amount,
		}
		defer func() { pendingGRC20Send = nil }()
		denom = alias
	case strings.Contains(denom, "/"):
		// This case exists only for a better error message: a denom with
		// slashes that isn't in grc20reg is likely a mistyped GRC20 path.
		// Without it, the default (native coin) branch would give a
		// confusing "requires one non-zero coin to be sent" error.
		panic(ufmt.Sprintf("GRC20 token %s not found in grc20reg", denom))
	default:
		// Native coin: only direct user-call (maketx call) is accepted, so
		// unsafe.OriginSend() describes coins that actually landed at this
		// realm. Intermediate code realms or `maketx run` ephemeral realms
		// can attach -send to the tx but spend it elsewhere.
		if !cur.Previous().IsUserCall() {
			panic("native transfer must be a direct user call (maketx call)")
		}
		sent := unsafe.OriginSend()
		if len(sent) != 1 || sent[0].Amount == 0 {
			panic("native transfer requires one non-zero coin to be sent")
		}
		if sent[0].Denom != denom || sent[0].Amount != amount {
			panic(ufmt.Sprintf(
				"sent coin %s does not match transfer args (denom=%s, amount=%d)",
				sent[0], denom, amount,
			))
		}
		// Hand the verified escrow off to OnSendPacket, which can no longer
		// safely read OriginSend (its PreviousRealm is the core realm).
		// The defer below guarantees we clear the slot in any exit path so
		// a leftover never bleeds into a later call.
		pendingNativeEscrow = &sent[0]
		defer func() { pendingNativeEscrow = nil }()
	}
	return transfer(cur, clientID, receiver, denom, amount, timeoutTimestamp, memo)
}

// VoucherSend is a convenience helper to send an IBC voucher token from the
// caller to the provided recipient.
func VoucherSend(cur realm, ibcDenom string, to address, amount int64) {
	inst := getVoucher(ibcDenom)
	if inst == nil {
		panic(ufmt.Errorf("voucher token not found for denom %s", ibcDenom))
	}
	teller := inst.ledger.ImpersonateTeller(cur.Previous().Address())
	if err := teller.Transfer(0, cur, to, amount); err != nil {
		panic(ufmt.Errorf("transfer voucher %s error: %v", ibcDenom, err))
	}
}

// VoucherApprove is a convenience helper to set a spender allowance for an IBC
// voucher token on behalf of the caller.
func VoucherApprove(cur realm, ibcDenom string, spender address, amount int64) {
	inst := getVoucher(ibcDenom)
	if inst == nil {
		panic(ufmt.Errorf("voucher token not found for denom %s", ibcDenom))
	}
	teller := inst.ledger.ImpersonateTeller(cur.Previous().Address())
	if err := teller.Approve(0, cur, spender, amount); err != nil {
		panic(ufmt.Errorf("approve voucher %s error: %v", ibcDenom, err))
	}
}

func transfer(cur realm, clientID, receiver, denom string, amount int64, timeoutTimestamp uint64, memo string) (
	packet types.MsgSendPacket, sequence uint64,
) {
	// unsafe.OriginCaller is the EOA that signed the tx; we use it as the
	// packet Sender so Transfer can also be invoked through a wrapper realm.
	// On the OnSendPacket side the same value is read back to verify the
	// packet Sender matches the signing EOA.
	data := NewFungibleTokenPacketData(
		denom,
		ufmt.Sprintf("%d", amount),
		unsafe.OriginCaller().String(),
		receiver,
		memo,
	)
	packet = types.MsgSendPacket{
		SourceClient: clientID,
		Payloads: []types.Payload{{
			SourcePort:      PortID,
			DestinationPort: PortID,
			Encoding:        EncodingProtobuf,
			Value:           data.ProtoMarshal(),
			Version:         V1,
		}},
		TimeoutTimestamp: timeoutTimestamp,
	}
	sequence = core.SendPacket(cross(cur), packet)
	return
}

// refundPacketToken is a non-crossing helper; rlm is the caller's live cur,
// needed only by unescrowNative which constructs a Banker.
func refundPacketToken(_ int, rlm realm, sourcePort, sourceClient, sender string, token Token) error {
	coin, err := token.ToCoin()
	if err != nil {
		return ufmt.Errorf("token to coin error: %v", err)
	}
	if token.Denom.HasPrefix(sourcePort, sourceClient) {
		// Re-mint voucher tokens that were burnt during OnSendPacket
		inst := getVoucher(coin.Denom)
		if inst == nil {
			return ufmt.Errorf("voucher token not found for denom %s", coin.Denom)
		}
		if err := inst.ledger.Mint(address(sender), coin.Amount); err != nil {
			return ufmt.Errorf("re-mint voucher error: %v", err)
		}
	} else if isGRC20Alias(coin.Denom) {
		// Non-IBC GRC20: return escrowed tokens to sender
		if err := unescrowGRC20(0, rlm, sender, coin); err != nil {
			return err
		}
	} else {
		// Native: return escrowed coins to sender
		if err := unescrowNative(0, rlm, sender, coin); err != nil {
			return err
		}
	}
	return nil
}

// unescrowGRC20 resolves the GRC20 alias and transfers the escrowed tokens
// back to the receiver via the token's RealmTeller. Non-crossing helper; rlm
// is needed by the grc20 teller API.
func unescrowGRC20(_ int, rlm realm, receiver string, coin chain.Coin) error {
	denomKey := resolveGRC20Alias(coin.Denom)
	token := grc20reg.Get(denomKey)
	if token == nil {
		return ufmt.Errorf("GRC20 token %s not found in grc20reg", denomKey)
	}
	teller := token.RealmTeller(0, rlm)
	if err := teller.Transfer(0, rlm, address(receiver), coin.Amount); err != nil {
		return ufmt.Errorf("unescrow GRC20 %s error: %v", denomKey, err)
	}
	subEscrowForDenom(coin)
	return nil
}

// unescrowNative sends the escrowed native coins back to the receiver via
// the banker. Non-crossing helper; rlm is the caller's live cur (transfer
// realm's own frame), needed to construct a Banker.
func unescrowNative(_ int, rlm realm, receiver string, coin chain.Coin) error {
	var (
		// TODO no app/clientID specific escrow address ?
		from   = rlm.Address()
		to     = address(receiver)
		amount = chain.NewCoins(coin)
		banker = banker.NewBanker(banker.BankerTypeRealmSend, rlm)
	)
	banker.SendCoins(from, to, amount)
	subEscrowForDenom(coin)
	return nil
}

// pendingSend records the token send that Transfer authorized for OnSendPacket.
type pendingSend struct {
	sender       string
	sourceClient string
	denom        string
	amount       int64
}

// Gno persists package-level vars to the realm store at end of tx.
// These pending values must be cleared before Transfer returns to avoid
// leaking state into the next tx. Transfer uses defers to guarantee the
// reset on every exit path.
var (
	// pendingNativeEscrow is set by Transfer's native branch and read by
	// OnSendPacket. It bridges the user-call boundary check, which is only
	// possible in Transfer where PreviousRealm() is the EOA, to the actual
	// escrow update done in OnSendPacket.
	pendingNativeEscrow *chain.Coin

	// pendingVoucherSend is set by Transfer's voucher branch after the direct
	// user-call guard passes. OnSendPacket consumes it before burning
	// user-owned voucher tokens, preventing direct core.SendPacket bypasses and
	// binding the packet to the asset the user explicitly requested.
	pendingVoucherSend *pendingSend

	// pendingGRC20Send is set by Transfer's GRC20 branch after the direct
	// user-call guard passes. OnSendPacket consumes it before escrowing
	// user-owned GRC20 tokens, preventing direct core.SendPacket bypasses and
	// binding the packet to the asset the user explicitly requested.
	pendingGRC20Send *pendingSend
)

