// VoucherApprove: success for IBC voucher token via MsgCall helper.
func main(cur realm) {
	var (
		chainID        = "chain-id-2"
		trustedHeight  = types.NewHeight(2, 2)
		clientState    = tmtesting.NewClientState(chainID, trustedHeight)
		apphash, _     = hex.DecodeString("0eadf50c7992d8e1366b8ea63ab7d1346de4762c3d449764ef7dc404ba48381f")
		trustedValset  = tmtesting.GenValset()
		consensusState = tmtesting.GenConsensusState(time.Now(), apphash, trustedValset.Hash())
		counterpartyID = "07-tendermint-42"
	)
	clientID := core.CreateClient(cross(cur), clientState, consensusState)
	core.RegisterCounterparty(cross(cur), clientID, [][]byte{[]byte("iavlStoreKey"), []byte("prefix2")}, counterpartyID)

	owner := cur.Previous().Address()
	spender := testutils.TestAddress("spender")

	mintVoucher(cur, clientID, counterpartyID, trustedHeight, owner)

	voucherDenom := transfer.NewDenom("uphoton", transfer.NewHop(transfer.PortID, clientID)).IBCDenom()
	// grc20reg keys tokens by rlmpath.symbol; the voucher symbol is the truncated
	// IBC hash (VoucherSymbol), not the full hash.
	token := grc20reg.MustGet("gno.land/r/aib/ibc/apps/transfer." + transfer.VoucherSymbol(voucherDenom))

	println("allowance before VoucherApprove:", token.Allowance(owner, spender))

	testing.SetRealm(testing.NewUserRealm(owner))
	transfer.VoucherApprove(cross(cur), voucherDenom, spender, 40)

	println("allowance after VoucherApprove:", token.Allowance(owner, spender))
}

