package main

// Regression test: a voucher send must be rejected when it does not originate
// from transfer.Transfer. OnSendPacket is reachable directly through the public
// core.SendPacket router, so the direct-user-call guard in transfer.Transfer is
// not sufficient on its own — OnSendPacket must also require that voucher (and
// GRC20) sends were initiated through transfer.Transfer, mirroring the existing
// native-branch pendingNativeEscrow check.
//
// Here core.SendPacket is invoked directly with a voucher payload whose Sender
// equals OriginCaller; the immediate caller is a realm (this main), not a user.
// Until the OnSendPacket-level guard lands this test FAILS because the send
// succeeds and burns the owner's voucher.

import (
	"encoding/hex"
	"time"

	tmtesting "gno.land/p/aib/ibc/lightclient/tendermint/testing"
	"gno.land/p/aib/ibc/types"

	"gno.land/p/aib/ics23"
	"gno.land/r/aib/ibc/apps/transfer"
	"gno.land/r/aib/ibc/core"
)

func main(cur realm) {
	var (
		chainID        = "chain-id-2"
		trustedHeight  = types.NewHeight(2, 2)
		clientState    = tmtesting.NewClientState(chainID, trustedHeight)
		apphash, _     = hex.DecodeString("0eadf50c7992d8e1366b8ea63ab7d1346de4762c3d449764ef7dc404ba48381f")
		trustedValset  = tmtesting.GenValset()
		consensusState = tmtesting.GenConsensusState(time.Now(), apphash, trustedValset.Hash())
		counterpartyID = "07-tendermint-42"
	)
	clientID := core.CreateClient(cross(cur), clientState, consensusState)
	core.RegisterCounterparty(cross(cur), clientID, [][]byte{[]byte("iavlStoreKey"), []byte("prefix2")}, counterpartyID)

	// The voucher owner is the signing EOA (OriginCaller). RecvPacket mints 100
